const a = [
  {"id":549,"text":"Blister cells and bite cells are seen in which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 634.","responses":[{"text":"Hereditary spherocytosis","correct":false,"visible":false},{"text":"Hemolytic uremic syndrome","correct":false,"visible":false},{"text":"Glucose-6-phosphate dehydrogenase (G6PD) deficiency","correct":true,"visible":false},{"text":"Sickle cell anemia","correct":false,"visible":false},{"text":"Pyruvate kinase deficiency","correct":false,"visible":false}]},{"id":550,"text":"Which of the following conditions is recombinant erythropoietin indicated for?","explanation":null,"reference":"Guan XZ, Wang LL, Pan X, et al. Clinical indications of recombinant human erythropoietin in a single center: a 10-year retrospective study. Frontiers in Pharmacology. Published 2020. https://pubmed.ncbi.nlm.nih.gov/32848738/","responses":[{"text":"Hemolytic anemia","correct":false,"visible":false},{"text":"Anemia due to malnutrition","correct":false,"visible":false},{"text":"Megaloblastic anemia","correct":false,"visible":false},{"text":"Anemia due to thalassemia","correct":false,"visible":false},{"text":"Anemia due to chronic kidney disease","correct":true,"visible":false}]},{"id":551,"text":"A patient may present with hemolytic anemia because of genetic mutations in protein synthesis. What is the most common inherited disorder causing anemia in humans in this connection?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 635.","responses":[{"text":"Glucose-6-phosphate dehydrogenase (G6PD) deficiency","correct":false,"visible":false},{"text":"Thalassemia syndrome","correct":false,"visible":false},{"text":"Hereditary spherocytosis","correct":false,"visible":false},{"text":"Sickle cell anemia","correct":true,"visible":false},{"text":"Autoimmune hemolytic anemia","correct":false,"visible":false}]},{"id":552,"text":"What type of anemia is caused by Diphyllobothrium latum (fish tapeworm)?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 645.","responses":[{"text":"Anemia of chronic disease","correct":false,"visible":false},{"text":"Pernicious anemia","correct":false,"visible":false},{"text":"Vitamin B12 deficiency anemia","correct":true,"visible":false},{"text":"Megaloblastic anemia","correct":false,"visible":false},{"text":"Iron deficiency anemia","correct":false,"visible":false}]},{"id":553,"text":"In which of the following conditions will non-neoplastic cells be seen?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 655.","responses":[{"text":"Myelodysplastic syndrome","correct":false,"visible":false},{"text":"Multiple myeloma","correct":false,"visible":false},{"text":"Non-hodgkin lymphoma","correct":false,"visible":false},{"text":"Aplastic anemia","correct":true,"visible":false},{"text":"Hairy cell leukemia","correct":false,"visible":false}]},{"id":554,"text":"What is the most common cause of iron deficiency anemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n651.","responses":[{"text":"Dietary deficiency","correct":true,"visible":false},{"text":"Gastrectomy","correct":false,"visible":false},{"text":"Increased demand during puberty","correct":false,"visible":false},{"text":"Malabsorption syndrome","correct":false,"visible":false},{"text":"Hookworm infestation","correct":false,"visible":false}]},{"id":555,"text":"Which of the following nail abnormalities is observed in iron deficiency anemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 652.","responses":[{"text":"Koilonychia","correct":true,"visible":false},{"text":"Pitting","correct":false,"visible":false},{"text":"Splinter hemorrhages","correct":false,"visible":false},{"text":"Erythronychia","correct":false,"visible":false},{"text":"Paronychia","correct":false,"visible":false}]},{"id":556,"text":"For diagnosis of iron deficiency anemia, which one of the following features is seen in the blood film?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 652.","responses":[{"text":"Poikilocytosis","correct":true,"visible":false},{"text":"Ringed sideroblasts","correct":false,"visible":false},{"text":"Target cells","correct":false,"visible":false},{"text":"Bite cells","correct":false,"visible":false},{"text":"Spherocytes","correct":false,"visible":false}]},{"id":557,"text":"A 9-year-old boy presents to the emergency department with left-sided hemiplegia. There is no history of head trauma to explain this presentation. If he had been diagnosed with anemia a few months ago, which of the following accounts for hemiplegia?","explanation":"The most likely diagnosis in this patient presenting with left-sided hemiplegia without a history of head trauma and a previous diagnosis of anemia, the most likely cause of hemiplegia is **sickle cell anemia**. Sickle cell anemia is a genetic disorder that leads to the production of abnormal hemoglobin, which can cause red blood cells to assume a sickle shape. These sickle-shaped cells can become lodged in blood vessels, leading to occlusions and infarctions. In the brain, this can result in a **stroke,** which could manifest as hemiplegia.\r\n\r\n---\r\n\r\nThalassemia is another hemoglobinopathy that can cause anemia but is less commonly associated with acute neurological events like stroke.\r\nFainting due to anemia can occur but would not cause unilateral hemiplegia.\r\nMultiple myeloma is a malignancy of plasma cells and is extremely rare in children; it also does not typically present with acute neurological deficits like hemiplegia.\r\nThrombotic thrombocytopenic purpura (TTP) is a disorder that can lead to small clots throughout the body, but isolated hemiplegia is not a typical presentation, and TTP is rare in children.","reference":"(1) Feather A, Randall D, Randall D, Waterhouse M, Waterhouse M. Kumar \u0026 Clark’s Clinical Medicine. 10th ed. Elsevier; 2021: 345.\r\n\r\n(2) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 48.","responses":[{"text":"Sickle cell anemia","correct":true,"visible":false},{"text":"Thalassemia","correct":false,"visible":false},{"text":"Thrombotic thrombocytopenic purpura","correct":false,"visible":false},{"text":"Fainting due to anemia","correct":false,"visible":false},{"text":"Multiple myeloma","correct":false,"visible":false}]},{"id":559,"text":"Which one of the following is used to check for the morphology of red blood cells (RBCs)?","explanation":null,"reference":"Mean corpuscular volume (Mcv): reference range, interpretation, collection and panels. Published online June 26, 2021. Accessed April 7, 2022. https://emedicine.medscape.com/article/2085770-overview","responses":[{"text":"Red cell distribution width (RDW)","correct":false,"visible":false},{"text":"Mean corpuscular hemoglobin (MCH)","correct":false,"visible":false},{"text":"Mean corpuscular hemoglobin concentration (MCHC)","correct":false,"visible":false},{"text":"Mean corpuscular volume (MCV)","correct":true,"visible":false},{"text":"Hematocrit","correct":false,"visible":false}]},{"id":560,"text":"Platelet infusion is contraindicated in which of the following conditions?","explanation":null,"reference":"Goel R, Ness PM, Takemoto CM, Krishnamurti L, King KE, Tobian AAR. Platelet transfusions in platelet consumptive disorders are associated with arterial thrombosis and in-hospital mortality. Blood. Published February 26, 2015. Accessed April 5, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4342358/","responses":[{"text":"Leukemia","correct":false,"visible":false},{"text":"Thrombotic thrombocytopenic purpura (TTP)","correct":true,"visible":false},{"text":"Aplastic anemia","correct":false,"visible":false},{"text":"Disseminated intravascular coagulation (DIC)","correct":false,"visible":false},{"text":"Ocular surgery","correct":false,"visible":false}]},{"id":561,"text":"What is the term used for the origin and synthesis of white blood cells (WBCs)?","explanation":null,"reference":"Leukopoiesis - mesh - ncbi. Accessed April 5, 2022. https://www.ncbi.nlm.nih.gov/mesh?Db=mesh\u0026Cmd=DetailsSearch\u0026Term=%22Leukopoiesis%22%5BMeSH+Terms%5D","responses":[{"text":"Hematopoiesis","correct":false,"visible":false},{"text":"Erythropoiesis","correct":false,"visible":false},{"text":"Granulocytopoiesis","correct":false,"visible":false},{"text":"Leukopoiesis","correct":true,"visible":false},{"text":"Thrombopoiesis","correct":false,"visible":false}]},{"id":562,"text":"In which one of the following conditions are Reed-Sternberg cells seen?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 588.","responses":[{"text":"Burkitt lymphoma","correct":false,"visible":false},{"text":"Leukemia","correct":false,"visible":false},{"text":"Hodgkin lymphoma","correct":true,"visible":false},{"text":"Mantle cell lymphoma","correct":false,"visible":false},{"text":"Non-Hodgkin lymphoma","correct":false,"visible":false}]},{"id":563,"text":"Which of the following is the diagnostic test for Rh incompatibility?","explanation":null,"reference":"Rh incompatibility: symptoms, diagnosis \u0026 treatments. Healthline. Published July 23, 2018. Accessed April 5, 2022. https://www.healthline.com/health/rh-incompatibility","responses":[{"text":"Chorionic villus sampling","correct":false,"visible":false},{"text":"Indirect Coombs test","correct":true,"visible":false},{"text":"Amniocentesis","correct":false,"visible":false},{"text":"Fetal middle cerebral arterial (MCA) doppler","correct":false,"visible":false},{"text":"Direct Coombs test","correct":false,"visible":false}]},{"id":564,"text":"What is the advantage of fingerprinting?","explanation":null,"reference":"Dow lecture slides: Hematology module, Forensic Medicine lecture slides, Personal Identity III, \"Galtonage or Dactylography I.E. Fingerprints.\"","responses":[{"text":"It does not require any special and expensive instruments","correct":false,"visible":false},{"text":"It is applicable for all people","correct":false,"visible":false},{"text":"It is applicable for all age groups","correct":false,"visible":false},{"text":"It enables absolute identification of an individual","correct":true,"visible":false},{"text":"No special training required","correct":false,"visible":false}]},{"id":565,"text":"Which of the following are long-lived phagocytic cells present abundantly in gastric tissue?","explanation":null,"reference":"Parihar A, Eubank TD, Doseff AI. Monocytes and macrophages regulate immunity through dynamic networks of survival and cell death. Journal of Innate Immunity. Published April 2010. Accessed April 5, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2956013/","responses":[{"text":"Neutrophils","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Monocytes","correct":false,"visible":false},{"text":"Macrophages","correct":true,"visible":false},{"text":"Dendritic cells","correct":false,"visible":false}]},{"id":566,"text":"Which of the following cells will be increased in a parasitic reaction?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 99.","responses":[{"text":"Monocytes","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Eosinophils","correct":true,"visible":false},{"text":"Neutrophils","correct":false,"visible":false},{"text":"Platelets","correct":false,"visible":false}]},{"id":567,"text":"What is the single best test to confirm iron deficiency anemia?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 941.","responses":[{"text":"Total iron-binding capacity (TIBC)","correct":false,"visible":false},{"text":"Bone marrow biopsy","correct":false,"visible":false},{"text":"Plasma iron level","correct":false,"visible":false},{"text":"Transferrin saturation","correct":false,"visible":false},{"text":"Plasma ferritin levels","correct":true,"visible":false}]},{"id":568,"text":"Which one of the following cells is dominant in viral infection?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 54.","responses":[{"text":"Eosinophils","correct":false,"visible":false},{"text":"Lymphocytes","correct":true,"visible":false},{"text":"Neutrophils","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Monocytes","correct":false,"visible":false}]},{"id":569,"text":"Which of the following patient factors is not important to note before a transfusion?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 934.","responses":[{"text":"Occupation","correct":true,"visible":false},{"text":"Date of birth","correct":false,"visible":false},{"text":"RhD group","correct":false,"visible":false},{"text":"Sex","correct":false,"visible":false},{"text":"Surname","correct":false,"visible":false}]},{"id":570,"text":"Which vaccines should be given at birth according to the expanded program on immunization (EPI) schedule?","explanation":null,"reference":"WHO, UNICEF. Integrated Management Of Neonatal \u0026 Childhood Illness. 2nd ed. Ministry of National Health Services; 2019: 11.","responses":[{"text":"BCG","correct":false,"visible":false},{"text":"OPV-0","correct":false,"visible":false},{"text":"BCG + OPV-I","correct":false,"visible":false},{"text":"BCG + OPV-0 + Rotavirus-I","correct":false,"visible":false},{"text":"BCG + OPV-0 + hep B","correct":true,"visible":false}]},{"id":572,"text":"Which of the following represents hot and cold antibodies respectively?","explanation":null,"reference":"Autoimmune hemolytic anemia - hematology and oncology. MSD Manual Professional Edition. Accessed April 5, 2022. https://www.msdmanuals.com/professional/hematology-and-oncology/anemias-caused-by-hemolysis/autoimmune-hemolytic-anemia","responses":[{"text":"IgD and IgE","correct":false,"visible":false},{"text":"IgG and IgM","correct":true,"visible":false},{"text":"IgG and IgE","correct":false,"visible":false},{"text":"IgM and IgE","correct":false,"visible":false},{"text":"IgA and IgE","correct":false,"visible":false}]},{"id":573,"text":"Bernard-Soulier is an inherited disease having giant, non-functional platelets with thrombocytopenia. What is the inheritance pattern of this disease?","explanation":null,"reference":"Almomani MH, Mangla A. Bernard soulier syndrome. In: StatPearls. StatPearls Publishing; 2022. Accessed April 5, 2022. http://www.ncbi.nlm.nih.gov/books/NBK557671/","responses":[{"text":"X-linked dominant","correct":false,"visible":false},{"text":"Mitochondrial inheritance","correct":false,"visible":false},{"text":"Autosomal dominant","correct":false,"visible":false},{"text":"Autosomal recessive","correct":true,"visible":false},{"text":"X-linked recessive","correct":false,"visible":false}]},{"id":574,"text":"A 5-year-old child is brought to the emergency department with extreme pain in his hands and feet. Examination reveals dactylitis (swelling of bones), pulmonary infiltrates, and signs and symptoms of anemia. While giving history, the child's parents talk about an inherited disorder that runs in the family. Which condition is the child most likely to be suffering from?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 48.","responses":[{"text":"Thalassemia","correct":false,"visible":false},{"text":"Immune thrombocytopenic purpura (ITP)","correct":false,"visible":false},{"text":"Sickle cell disease","correct":true,"visible":false},{"text":"Disseminated intravascular coagulation (DIC)","correct":false,"visible":false},{"text":"Thrombotic thrombocytopenic purpura (TTP)","correct":false,"visible":false}]},{"id":575,"text":"Which one of the following is true about aplastic anemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 653, 654.","responses":[{"text":"Hypercellular bone marrow","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Patients do not require blood support","correct":false,"visible":false},{"text":"Hepatosplenomegaly is not present","correct":true,"visible":false},{"text":"It is not immune mediated","correct":false,"visible":false}]},{"id":576,"text":"Which one of the following constituents is present in hemoglobin A (HbA)?","explanation":null,"reference":"Hemoglobin a - an overview | sciencedirect topics. Accessed April 5, 2022. https://www.sciencedirect.com/topics/neuroscience/hemoglobin-a","responses":[{"text":"2 zeta and 2 epsilon chains","correct":false,"visible":false},{"text":"2 alpha and 2 gamma chains","correct":false,"visible":false},{"text":"2 alpha and 2 delta chains","correct":false,"visible":false},{"text":"2 delta and 2 gamma chains","correct":false,"visible":false},{"text":"2 alpha and 2 beta chains","correct":true,"visible":false}]},{"id":577,"text":"Which one of the following is correct about mixed cellularity lymphoma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 63.","responses":[{"text":"Does not involve abdominal lymph nodes","correct":false,"visible":false},{"text":"Reed-Sternberg cells are not present","correct":false,"visible":false},{"text":"High eosinophils count","correct":true,"visible":false},{"text":"Poor prognosis","correct":false,"visible":false},{"text":"Not caused by Epstein-Barr virus","correct":false,"visible":false}]},{"id":578,"text":"A 24-year-old man is brought to the emergency after a motorcycle accident. He is bleeding profusely from the wound on his leg. He has no previous medical or surgical history. When a blood smear is performed, what type of red blood cells are likely to be seen?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 631.","responses":[{"text":"Macrocytic hypochromic","correct":false,"visible":false},{"text":"Normocytic hypochromic","correct":false,"visible":false},{"text":"Normocytic normochromic","correct":true,"visible":false},{"text":"Microcytic hypochromic","correct":false,"visible":false},{"text":"Macrocytic hypochromic","correct":false,"visible":false}]},{"id":579,"text":"Which one of the following is the most common type of Hodgkin lymphoma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 ReviewPathoma.com; 2021: 62.","responses":[{"text":"Nodular lymphocyte predominant","correct":false,"visible":false},{"text":"Lymphocyte rich","correct":false,"visible":false},{"text":"Lymphocyte depleted","correct":false,"visible":false},{"text":"Mixed cellularity","correct":false,"visible":false},{"text":"Nodular sclerosis","correct":true,"visible":false}]},{"id":580,"text":"A 10-year-old child is brought to the hospital with complaints of bloody diarrhea for the past 3 days. Examination and labs reveal an acute kidney injury along with thrombocytopenia. Upon taking history, the parents said that their child had an E. coli infection for the past few days. Which one of the following cells is most likely to be seen in this condition?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 33.","responses":[{"text":"Bite cells","correct":false,"visible":false},{"text":"Schistocytes","correct":true,"visible":false},{"text":"Tear drop cells","correct":false,"visible":false},{"text":"Sickle cells","correct":false,"visible":false},{"text":"Heinz bodies","correct":false,"visible":false}]},{"id":581,"text":"A 7-year-old African kid is brought to the clinic with a swelling around his jaw that has been slowly increasing in size over the past few months. Biopsy of the mass reveals a starry sky appearance. What is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 62.","responses":[{"text":"Burkitt lymphoma","correct":true,"visible":false},{"text":"Mantle cell lymphoma","correct":false,"visible":false},{"text":"Hairy cell leukemia","correct":false,"visible":false},{"text":"Hodgkin lymphoma","correct":false,"visible":false},{"text":"Follicular lymphoma","correct":false,"visible":false}]},{"id":582,"text":"Which one of the following statements is true for Hodgkin's lymphoma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 62.","responses":[{"text":"Lacunar cells are not present","correct":false,"visible":false},{"text":"CD-15 and CD-30 markers are present","correct":true,"visible":false},{"text":"Absence of Reed Sternberg cells","correct":false,"visible":false},{"text":"No eosinophilia","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":583,"text":"Which one of the following conditions is most likely to show positive Coomb's test?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 643.","responses":[{"text":"Hodgkins lymphoma","correct":false,"visible":false},{"text":"Disseminated intravascular coagulation (DIC)","correct":false,"visible":false},{"text":"Autoimmune hemolytic anemia","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Pernicious anemia","correct":false,"visible":false}]},{"id":584,"text":"A 32-year-old female had to undergo a total gastrectomy. After almost 2 years, she started developing weakness, shortness of breath, occasional dizziness and difficulty in walking. She went to her doctor to get a check-up done. On examining her, the doctor noticed that she also had pale skin and yellowing of sclera. What would be the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 45-46.","responses":[{"text":"Hemolytic anemia","correct":false,"visible":false},{"text":"Megaloblastic anemia","correct":true,"visible":false},{"text":"Normocytic normochromic anemia","correct":false,"visible":false},{"text":"Microcytic hypochromic anemia","correct":false,"visible":false},{"text":"Pernicious anemia","correct":false,"visible":false}]},{"id":585,"text":"Which pattern of serum protein electrophoresis is seen in multiple myeloma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 63.","responses":[{"text":"Monoclonal band","correct":true,"visible":false},{"text":"Double peak","correct":false,"visible":false},{"text":"Polyclonal band","correct":false,"visible":false},{"text":"Diffuse band","correct":false,"visible":false},{"text":"Slumped band","correct":false,"visible":false}]},{"id":586,"text":"Which of the following chromosomal translocations is found in chronic myelogenous leukemia?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 58.","responses":[{"text":"t(9;22)","correct":true,"visible":false},{"text":"t(4;14)","correct":false,"visible":false},{"text":"t(8;21)","correct":false,"visible":false},{"text":"t(15;17)","correct":false,"visible":false},{"text":"Trisomy 12q","correct":false,"visible":false}]},{"id":587,"text":"What is the term used for abnormal and uncontrolled production of white blood cells (WBCs)?","explanation":null,"reference":"Chennamadhavuni A, Lyengar V, Shimanovsky A. Leukemia. In: StatPearls. StatPearls Publishing; 2022. Accessed April 7, 2022. http://www.ncbi.nlm.nih.gov/books/NBK560490/","responses":[{"text":"Lymphocytosis","correct":false,"visible":false},{"text":"Leukopenia","correct":false,"visible":false},{"text":"Leukemia","correct":true,"visible":false},{"text":"Leukopoiesis","correct":false,"visible":false},{"text":"Lymphopenia","correct":false,"visible":false}]},{"id":588,"text":"Which component of blood is best for transfusion in case of multiple coagulation factor deficiencies?","explanation":null,"reference":"William NS, O’Connell PR, McCaskie AW, eds. Bailey \u0026 Love’s Short Practice of Surgery. 27th ed. CRC Press, Taylor \u0026 Francis Group; 2018: 21.","responses":[{"text":"Cryoprecipitate","correct":false,"visible":false},{"text":"Fresh frozen plasma","correct":true,"visible":false},{"text":"Packed red cells","correct":false,"visible":false},{"text":"Pooled platelets","correct":false,"visible":false},{"text":"Whole blood","correct":false,"visible":false}]},{"id":589,"text":"Which one of the following is used as an antidote for heparin?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 939.","responses":[{"text":"Vitamin C","correct":false,"visible":false},{"text":"Vitamin K","correct":false,"visible":false},{"text":"Protamine sulfate","correct":true,"visible":false},{"text":"Succimer","correct":false,"visible":false},{"text":"Fresh frozen plasma (FFP)","correct":false,"visible":false}]},{"id":590,"text":"Which of the following is the most abundant cell type in the blood?","explanation":null,"reference":"Dean L. Blood and the Cells It Contains. National Center for Biotechnology Information (US); 2005. Accessed April 7, 2022. https://www.ncbi.nlm.nih.gov/books/NBK2263/","responses":[{"text":"Lymphocytes","correct":false,"visible":false},{"text":"Platelets","correct":false,"visible":false},{"text":"Granulocyte","correct":false,"visible":false},{"text":"Erythrocytes","correct":true,"visible":false},{"text":"Monocytes","correct":false,"visible":false}]},{"id":591,"text":"Intravascular hemolysis is one of the causes of hemolytic anemia. Which one of the following is not a feature of intravascular hemolysis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 47.","responses":[{"text":"Raised haptoglobin","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Hemosiderinuria","correct":false,"visible":false},{"text":"Urobilinogen in urine","correct":false,"visible":false},{"text":"Hemoglobinemia","correct":false,"visible":false}]},{"id":592,"text":"Which of the following blood cells have phagocytic activity?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 186.","responses":[{"text":"Megakaryocytes","correct":false,"visible":false},{"text":"Platelets","correct":false,"visible":false},{"text":"Neutrophils","correct":true,"visible":false},{"text":"Fibroblasts","correct":false,"visible":false},{"text":"Reticulocytes","correct":false,"visible":false}]},{"id":593,"text":"Which of the following is most likely seen due to platelet disorders?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 32.","responses":[{"text":"Normal platelet count with raised PT and aPTT","correct":false,"visible":false},{"text":"Thrombocytopenia with normal PT and aPTT","correct":true,"visible":false},{"text":"Normal platelet count with normal PT and aPTT","correct":false,"visible":false},{"text":"Thrombocytopenia with raised PT but normal aPTT","correct":false,"visible":false},{"text":"Thrombocytopenia with raised PT and aPTT","correct":false,"visible":false}]},{"id":594,"text":"Which of the following is not a characteristic feature of hemolytic anemia?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 47.","responses":[{"text":"Increased neutrophil count","correct":false,"visible":false},{"text":"Reduced plasma haptoglobin level","correct":false,"visible":false},{"text":"Decreased reticulocyte count","correct":true,"visible":false},{"text":"Increased unconjugated bilirubin","correct":false,"visible":false},{"text":"Excess urinary urobilinogen","correct":false,"visible":false}]},{"id":595,"text":"What is the mechanism of action of tacrolimus?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 89.","responses":[{"text":"Inhibition of inosine monophosphate dehydrogenase","correct":false,"visible":false},{"text":"Inhibition of calcineurin","correct":true,"visible":false},{"text":"Inhibition of purine synthesis","correct":false,"visible":false},{"text":"Destruction of T-cells","correct":false,"visible":false},{"text":"Inhibition of IL-2 action","correct":false,"visible":false}]},{"id":596,"text":"A 30-year-old lady received 6 units of blood and developed carpopedal spasm and twitching in her hands, along with flushing of the face. What can be given to relieve her condition?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 663.","responses":[{"text":"Intravenous 5% dextrose","correct":false,"visible":false},{"text":"Intravenous calcium gluconate","correct":true,"visible":false},{"text":"Intravenous water","correct":false,"visible":false},{"text":"Intravenous normal saline","correct":false,"visible":false},{"text":"Intravenous diazepam","correct":false,"visible":false}]},{"id":598,"text":"The diagnosis of Hodgkin lymphoma depends on what histologic finding?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 62.","responses":[{"text":"Infiltrative eosinophils","correct":false,"visible":false},{"text":"Sezary cells","correct":false,"visible":false},{"text":"Pautrier microabscesses","correct":false,"visible":false},{"text":"Auer rods","correct":false,"visible":false},{"text":"Reed-Sternberg cells","correct":true,"visible":false}]},{"id":599,"text":"Which coagulation factor is deficient in hemophilia B?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 34.","responses":[{"text":"IX","correct":true,"visible":false},{"text":"V","correct":false,"visible":false},{"text":"XI","correct":false,"visible":false},{"text":"II","correct":false,"visible":false},{"text":"VIII","correct":false,"visible":false}]},{"id":600,"text":"Which vitamin deficiency can lead to a protein C deficiency?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 121.","responses":[{"text":"Vitamin A","correct":false,"visible":false},{"text":"Vitamin K","correct":true,"visible":false},{"text":"Vitamin B","correct":false,"visible":false},{"text":"Vitamin D","correct":false,"visible":false},{"text":"Vitamin E","correct":false,"visible":false}]},{"id":602,"text":"Which of the following types of immunity occurs when an individual is administered with an immunoglobulin made in another host?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 114.","responses":[{"text":"Artificial","correct":false,"visible":false},{"text":"Active","correct":false,"visible":false},{"text":"Innate","correct":false,"visible":false},{"text":"Natural","correct":false,"visible":false},{"text":"Passive","correct":true,"visible":false}]},{"id":604,"text":"Which one of the following conversions uses vitamin B12 as a co-factor?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 37.","responses":[{"text":"Serine to glycine","correct":false,"visible":false},{"text":"Succinyl CoA to succinate","correct":false,"visible":false},{"text":"Homocysteine to methionine","correct":true,"visible":false},{"text":"Pyruvate to acetyl coA","correct":false,"visible":false},{"text":"Oxaloacetate to citrate","correct":false,"visible":false}]},{"id":605,"text":"Which of the following conditions is true about the leukemoid reaction?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n99.","responses":[{"text":"Response to an infection","correct":true,"visible":false},{"text":"Blood smear contains mature white blood cells and red blood cells","correct":false,"visible":false},{"text":"Only involves neutrophils","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Always presents with abnormal bone marrow","correct":false,"visible":false}]},{"id":606,"text":"What is the movement of white blood cells in to the tissues in response to interleukins called?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 13.","responses":[{"text":"Clumping","correct":false,"visible":false},{"text":"Precipitation","correct":false,"visible":false},{"text":"Proliferation of lymphocytes","correct":false,"visible":false},{"text":"Diapedesis","correct":false,"visible":false},{"text":"Chemotaxis","correct":true,"visible":false}]},{"id":607,"text":"What type of vaccine is the diphtheria vaccine?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 266.","responses":[{"text":"Immunoglobulin","correct":false,"visible":false},{"text":"Subunit","correct":false,"visible":false},{"text":"Toxin","correct":false,"visible":false},{"text":"Live attenuated","correct":false,"visible":false},{"text":"Toxoid","correct":true,"visible":false}]},{"id":608,"text":"The erythropoietin receptor belongs to which class of receptors?","explanation":null,"reference":"Erythropoietin receptor - an overview | sciencedirect topics. Accessed April 7, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/erythropoietin-receptor","responses":[{"text":"Tyrosine kinase receptor","correct":false,"visible":false},{"text":"G protein-coupled receptor","correct":false,"visible":false},{"text":"Ligand-gated ion channel","correct":false,"visible":false},{"text":"Intracellular receptor","correct":false,"visible":false},{"text":"Cytokine receptor","correct":true,"visible":false}]},{"id":609,"text":"Terminal deoxynucleotidyl transferase (TdT) is a marker for which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 55.","responses":[{"text":"Mature B and T cells","correct":false,"visible":false},{"text":"Reed-Sternberg cells","correct":false,"visible":false},{"text":"NK cells and granulocytes","correct":false,"visible":false},{"text":"Germinal centre B cells","correct":false,"visible":false},{"text":"Pre-B and pre-T cells","correct":true,"visible":false}]},{"id":610,"text":"In sickle cell anemia, glutamate at the 6th position of the beta chain of hemoglobin is substituted by which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 47.","responses":[{"text":"Valine","correct":true,"visible":false},{"text":"Proline","correct":false,"visible":false},{"text":"Tyrosine","correct":false,"visible":false},{"text":"Lysine","correct":false,"visible":false},{"text":"Glycine","correct":false,"visible":false}]},{"id":611,"text":"Which of the following agents is a potent iron chelator?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 428.","responses":[{"text":"Ferrous sulfate","correct":false,"visible":false},{"text":"Unithiol","correct":false,"visible":false},{"text":"Succimer","correct":false,"visible":false},{"text":"Ferrous gluconate","correct":false,"visible":false},{"text":"Deferoxamine","correct":true,"visible":false}]},{"id":612,"text":"A 24-year-old presents with bruises in the emergency department. Laboratory results showed normal bleeding time but prolonged prothrombin time (PT) and partial thromboplastin time (PTT). Which one of the following is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 32-34.","responses":[{"text":"von Willebrand factor (VWF)","correct":false,"visible":false},{"text":"Thrombocytopenia","correct":false,"visible":false},{"text":"Coagulation disorder","correct":true,"visible":false},{"text":"Immune thrombocytopenic purpura","correct":false,"visible":false},{"text":"Thrombotic thrombocytopenic purpura (TTP)","correct":false,"visible":false}]},{"id":613,"text":"Which one of the following antibodies of the recipient is responsible for causing urticaria in the donor's blood?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n201.","responses":[{"text":"Ig G antibodies","correct":false,"visible":false},{"text":"Ig A antibodies","correct":false,"visible":false},{"text":"Ig D antibodies","correct":false,"visible":false},{"text":"Ig M antibodies","correct":false,"visible":false},{"text":"Ig E antibodies","correct":true,"visible":false}]},{"id":614,"text":"A 35-year-old man with a history of intravenous (IV) drug abuse has generalized lymphadenopathy. Which of the following tests would help in finding the cause of his lymphadenopathy?","explanation":null,"reference":"(1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 312. (2) Hematology module, Medicine lecture slides, Topic: Approach to a patient of lymphadenopathy with and without splenomegaly, Sub-topic: location.","responses":[{"text":"HIV serology","correct":true,"visible":false},{"text":"Bone marrow biopsy","correct":false,"visible":false},{"text":"Histopathology","correct":false,"visible":false},{"text":"Ultrasonography","correct":false,"visible":false},{"text":"Complete blood count (CBC)","correct":false,"visible":false}]},{"id":615,"text":"A 37-year-old woman presents to the outpatient department with a complaint of a lump in the right breast. The general physical examination concludes mass in the right upper quadrant of the breast and an enlarged right axial lymph node. She was diagnosed with Hodgkin lymphoma 7 years ago but was treated for it and completely cured. What is the most likely diagnosis of this patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n610.","responses":[{"text":"Fibroadenoma","correct":false,"visible":false},{"text":"Hodgkin lymphoma","correct":false,"visible":false},{"text":"Acute myeloid leukemia","correct":false,"visible":false},{"text":"Breast cancer","correct":true,"visible":false},{"text":"Non-Hodgkin lymphoma","correct":false,"visible":false}]},{"id":617,"text":"What is the most common gene mutation in alpha thalassemia?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 44.","responses":[{"text":"Nonsense mutation","correct":false,"visible":false},{"text":"Missense mutation","correct":false,"visible":false},{"text":"Splice mutation","correct":false,"visible":false},{"text":"Gene deletion","correct":true,"visible":false},{"text":"Frameshift mutation","correct":false,"visible":false}]},{"id":618,"text":"What is immunization to the whole community referred to as?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 115.","responses":[{"text":"Innate immunity","correct":false,"visible":false},{"text":"Herd immunity","correct":true,"visible":false},{"text":"Active immunity","correct":false,"visible":false},{"text":"Adaptive immunity","correct":false,"visible":false},{"text":"Passive immunity","correct":false,"visible":false}]},{"id":620,"text":"Stunted and notched upper central incisors are most likely to be found in which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 381.","responses":[{"text":"Scurvy","correct":false,"visible":false},{"text":"Rickets","correct":false,"visible":false},{"text":"Congenital syphilis","correct":true,"visible":false},{"text":"Fetal alcohol syndrome","correct":false,"visible":false},{"text":"Plummer vinson syndrome","correct":false,"visible":false}]},{"id":621,"text":"Which of the following are non-neoplastic cells?","explanation":null,"reference":"Nodular sclerosis - an overview | sciencedirect topics. Accessed April 7, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/nodular-sclerosis","responses":[{"text":"Blast cells","correct":true,"visible":false},{"text":"Popcorn cells","correct":false,"visible":false},{"text":"Mononuclear cells","correct":false,"visible":false},{"text":"Lacunar cells","correct":false,"visible":false},{"text":"Reed Steerberg cells","correct":false,"visible":false}]},{"id":624,"text":"Which of the following is implicated in Hodgkin's disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 588.","responses":[{"text":"Skin","correct":false,"visible":false},{"text":"Bone marrow","correct":false,"visible":false},{"text":"Thymus","correct":false,"visible":false},{"text":"Lymph nodes","correct":true,"visible":false},{"text":"Blood","correct":false,"visible":false}]},{"id":629,"text":"A girl presented to the emergency with a complaint of easy bruising and petechia, which is on and off. Her brother also suffered from the same condition. The lab results of the girl showed increased bleeding and partial thromboplastin time. Which one of the following conditions was she suffering from?","explanation":"The clinical presentation of easy bruising, petechiae, along with a family history of similar symptoms in her brother, suggests a possible **inherited bleeding disorder**. The laboratory findings of increased bleeding time and prolonged partial thromboplastin time (PTT) further narrow down the diagnosis to **von Willebrand disease**. This inherited bleeding disorder is characterized by a deficiency or dysfunction of von Willebrand factor (vWF), a crucial protein for normal platelet function and coagulation. Patients with von Willebrand disease often experience spontaneous mucocutaneous bleeding, such as easy bruising and petechiae, as well as prolonged bleeding after minor injuries or surgeries.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 34.","responses":[{"text":"Glanzmann thrombasthenia","correct":false,"visible":false},{"text":"Hemophilia","correct":false,"visible":false},{"text":"von Willebrand disease","correct":true,"visible":false},{"text":"Immune thrombocytopenia","correct":false,"visible":false},{"text":"Disseminated intravascular coagulation","correct":false,"visible":false}]},{"id":630,"text":"A female presented with gingival bleeding, fever, and headache to the outpatient department (OPD). Her lab results showed normal partial thromboplastin time (PTT) and prothrombin time (PT) but increased bleeding time. Her blood smear showed the presence of schistocytes. Which one is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 33.","responses":[{"text":"Disseminated intravascular coagulation","correct":false,"visible":false},{"text":"Immune thrombocytopenia","correct":false,"visible":false},{"text":"Thrombotic thrombocytopenic purpura","correct":true,"visible":false},{"text":"von Willebrand disease","correct":false,"visible":false},{"text":"Hemophilia","correct":false,"visible":false}]},{"id":636,"text":"Which surgery most commonly causes deep vein thrombosis (DVT)?","explanation":null,"reference":"Bui MH, Hung DD, Vinh PQ, Hiep NH, Anh LL, Dinh TC. Frequency and risk factor of lower-limb deep vein thrombosis after major orthopedic surgery in vietnamese patients. Open Access Macedonian Journal of Medical Sciences. Published December 20, 2019. Accessed April 8, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7084020/","responses":[{"text":"Cardiothoracic surgery","correct":false,"visible":false},{"text":"Coronary artery bypass grafting (CABG)","correct":false,"visible":false},{"text":"Hip surgery","correct":true,"visible":false},{"text":"Carpal tunnel surgery","correct":false,"visible":false},{"text":"Thyroid surgery","correct":false,"visible":false}]},{"id":637,"text":"What is the diagnostic test for deep vein thrombosis (DVT)?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 187.","responses":[{"text":"D-dimer test","correct":false,"visible":false},{"text":"Doppler ultrasound","correct":true,"visible":false},{"text":"Magnetic resonance imaging (MRI)","correct":false,"visible":false},{"text":"Venography","correct":false,"visible":false},{"text":"Computed tomography (CT)","correct":false,"visible":false}]},{"id":638,"text":"Which drug should be given to a patient with deep vein thrombosis (DVT)?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 210.","responses":[{"text":"Streptokinase","correct":false,"visible":false},{"text":"Coumarin","correct":false,"visible":false},{"text":"Clopidogrel","correct":false,"visible":false},{"text":"Heparin","correct":true,"visible":false},{"text":"Alteplase","correct":false,"visible":false}]},{"id":671,"text":"A 6-year-old child, diagnosed with hereditary spherocytosis, complained of increased frequency of blood transfusions. Blood complete picture shows Hb=6.5 gm/dL, reticulocyte count=20%, TLC=4000/mm³, platelets=100,000/mm³. What will be the most appropriate treatment for this child?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 633.","responses":[{"text":"Repeated transfusions with iron chelation","correct":false,"visible":false},{"text":"Hydroxyurea","correct":false,"visible":false},{"text":"Bone marrow transplant","correct":false,"visible":false},{"text":"Splenectomy","correct":true,"visible":false},{"text":"Corticosteroids with antithymhocytic globulin","correct":false,"visible":false}]},{"id":677,"text":"A 24-year-old boy was brought to the emergency with a petechial hemorrhage with no fever. Upon examination, he had mild splenomegaly but no neurological symptoms. His laboratory results showed prolonged bleeding time but normal prothrombin time (PT) and partial thromboplastin time (PTT). Which one of the following is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 32.","responses":[{"text":"Immune thrombocytopenic purpura (ITP)","correct":true,"visible":false},{"text":"Thrombotic thrombocytopenic purpura (TTP)","correct":false,"visible":false},{"text":"Hemolytic-uremic syndrome (HUS)","correct":false,"visible":false},{"text":"Hemophilia","correct":false,"visible":false},{"text":"Disseminated intravascular coagulation (DIC)","correct":false,"visible":false}]},{"id":678,"text":"A patient presented with disseminated intravascular coagulation (DIC) due to sepsis by gram-negative bacteria in the emergency. Which one of the following is the first step for the management of DIC in this patient?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 197.","responses":[{"text":"IV antibiotic + IV hydration","correct":true,"visible":false},{"text":"Platelet","correct":false,"visible":false},{"text":"Whole blood","correct":false,"visible":false},{"text":"Cryoprecipitate","correct":false,"visible":false},{"text":"Fresh frozen plasma","correct":false,"visible":false}]},{"id":679,"text":"Which of the following is not correct about non-Hodgkin lymphoma?","explanation":null,"reference":"(1) Le, Tao, and Vikas Bhushan. First Aid for the USMLE Step 1 2022. 32nd ed., McGraw-Hill Education, 2022: 437. \r\n(2) Kumar, Vinay, et al. Robbins and Cotran Pathologic Basis of Disease. 9th ed., Elsevier Saunders, 2015: 597, 603.","responses":[{"text":"t(14:18) in follicular lymphoma results in dysregulated BCL2 expression","correct":false,"visible":false},{"text":"Males have a slightly higher risk","correct":false,"visible":false},{"text":"Epstein-Barr virus is associated with post-transplant non-Hodgkin lymphoma","correct":false,"visible":false},{"text":"Median age is 65-70 years","correct":false,"visible":false},{"text":"Burkitt lymphoma is most aggressive and incurable","correct":true,"visible":false}]},{"id":680,"text":"What antibody is found in antiphospholipid syndrome?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 19.","responses":[{"text":"Anti-cyclic citrullinated peptide (anti-CCP) antibody","correct":false,"visible":false},{"text":"Rheumatoid factor (RF)","correct":false,"visible":false},{"text":"Antinuclear antibody (ANA)","correct":false,"visible":false},{"text":"Anticardiolipin antibody","correct":true,"visible":false},{"text":"Anti-double stranded DNA (Anti-dsDNA) antibody","correct":false,"visible":false}]},{"id":685,"text":"Which of the following is not a feature of polycythemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n619.","responses":[{"text":"Headache","correct":false,"visible":false},{"text":"Pruritus","correct":false,"visible":false},{"text":"Cyanosis","correct":false,"visible":false},{"text":"Hepatosplenomegaly","correct":false,"visible":false},{"text":"Hypotension","correct":true,"visible":false}]},{"id":692,"text":"A man has a history of eczema and allergic asthma. Which diagnostic test is performed?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 416.","responses":[{"text":"Urinalysis","correct":false,"visible":false},{"text":"Red blood cell sedimentation","correct":false,"visible":false},{"text":"Peripheral blood smear","correct":false,"visible":false},{"text":"Chest X-ray","correct":false,"visible":false},{"text":"Complete blood count (CBC)","correct":true,"visible":false}]},{"id":698,"text":"A 4-year-old girl presents with skin pallor for the past 3 days. One week ago she had a history of bloody diarrhea. Examination showed petechiae on the upper limbs. Laboratory studies revealed Hb 7.1 g/dl, reticulocytes 14%, platelets 30x 109/L, and normal WBC count. The renal function is deranged. The peripheral smear features numerous schistocytes and occasional nucleated RBC. Given the findings, which of the following bacteria is involved in the pathophysiology of disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 790","responses":[{"text":"Shigella dysenteriae","correct":true,"visible":false},{"text":"Streptococcus pyogenes","correct":false,"visible":false},{"text":"Helicobacter pylori","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Salmonella typhi","correct":false,"visible":false}]},{"id":704,"text":"Spontaneous bleeding becomes evident when the platelet count falls below which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 657.","responses":[{"text":"20,000 platelets per microliter blood","correct":true,"visible":false},{"text":"40,000 platelets per microliter blood","correct":false,"visible":false},{"text":"100,000 platelets per microliter blood","correct":false,"visible":false},{"text":"60,000 platelets per microliter blood","correct":false,"visible":false},{"text":"75,000 platelets per microliter blood","correct":false,"visible":false}]},{"id":710,"text":"A child presents with an enlarged spleen and jaundice. His laboratory findings include an increased red blood cell width, spherocytes with loss of pallor, and increased mean corpuscular hemoglobin concentration (MCHC). Which of the following would be a possible diagnosis?","explanation":"**Hereditary spherocytosis** is an inherited hemolytic anemia characterized by a defect in the structural proteins of red blood cell membranes, leading to spherical-shaped red blood cells (spherocytes) and increased MCHC. The loss of pallor is a characteristic feature of spherocytes when examined under a microscope.\r\n\r\nThe combination of splenomegaly and jaundice in hereditary spherocytosis is due to the excessive destruction of these abnormal spherocytes in the spleen, leading to hemolysis and the release of bilirubin, causing jaundice.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 47","responses":[{"text":"Aplastic anemia","correct":false,"visible":false},{"text":"Hereditary spherocytosis","correct":true,"visible":false},{"text":"Pernicious anemia","correct":false,"visible":false},{"text":"Hodgkin lymphoma","correct":false,"visible":false},{"text":"Myeloproliferative disorder","correct":false,"visible":false}]},{"id":711,"text":"What is most commonly not found among all types of myeloproliferative disorders?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 58.","responses":[{"text":"Hypocellular bone marrow","correct":true,"visible":false},{"text":"JAK 2 kinase mutation","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Hypercellular bone marrow","correct":false,"visible":false},{"text":"Involves myoblasts","correct":false,"visible":false}]},{"id":712,"text":"Which of the following is a cause of neutropenia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n653.","responses":[{"text":"Aplastic anemia","correct":true,"visible":false},{"text":"Allergic reaction","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Addison's disease","correct":false,"visible":false},{"text":"Steroids","correct":false,"visible":false}]},{"id":713,"text":"Which of the following statements is true about acute myelogenous leukemia?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 56.","responses":[{"text":"Not caused due to alkylating agents or radiation","correct":false,"visible":false},{"text":"Gum infiltration","correct":true,"visible":false},{"text":"No association with Down syndrome","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Involves cyclin D1 mutation","correct":false,"visible":false}]},{"id":714,"text":"Patients with severe liver disease are most likely to develop which of the following pathological findings?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 35.","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Patient will be unresponsive to vitamin K injection","correct":true,"visible":false},{"text":"Defect in Gp1B receptors of platelets","correct":false,"visible":false},{"text":"Normal PT and APTT","correct":false,"visible":false},{"text":"Increased bleeding time","correct":false,"visible":false}]},{"id":715,"text":"Which of the following substances are released from granules in basophils?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n83.","responses":[{"text":"Histamine and heparin","correct":true,"visible":false},{"text":"vWF","correct":false,"visible":false},{"text":"ADP and calcium ions","correct":false,"visible":false},{"text":"Hemoglobin","correct":false,"visible":false},{"text":"Fibrinogen and fibronectin","correct":false,"visible":false}]},{"id":717,"text":"What is observed in chronic myeloid leukemia?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 58.","responses":[{"text":"Eosinophilia with increased IgE","correct":false,"visible":false},{"text":"Plasma cell degranulation","correct":false,"visible":false},{"text":"JAK 2 tyrosine kinase mutation","correct":false,"visible":false},{"text":"Tissue necrosis","correct":false,"visible":false},{"text":"Basophilia","correct":true,"visible":false}]},{"id":718,"text":"In which of the following conditions will eosinophilia be observed?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 54.","responses":[{"text":"Septic shock","correct":false,"visible":false},{"text":"Chronic inflammation","correct":false,"visible":false},{"text":"Autoimmune hemolytic anemia","correct":false,"visible":false},{"text":"Cushing's syndrome","correct":false,"visible":false},{"text":"Protozoal and parasitic infection","correct":true,"visible":false}]},{"id":732,"text":"A 65-year-old man presented to the clinic with complaints of severe backache. The doctor ordered laboratory tests that revealed a hemoglobin level of 7.0 mg/dL and serum creatinine of 2.0 mg/dL. Which of the following findings would also be included in the report?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 63.","responses":[{"text":"Hypercalcemia","correct":true,"visible":false},{"text":"Oxaluria","correct":false,"visible":false},{"text":"Hypocalcemia","correct":false,"visible":false},{"text":"Hypernatremia","correct":false,"visible":false},{"text":"Hyperkalemia","correct":false,"visible":false}]},{"id":734,"text":"Which of the following hemoglobins are present in thalassemia major?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n640.","responses":[{"text":"Normal HbA, increased HbA2 (2-8%)","correct":false,"visible":false},{"text":"Normal HbA, increased HbA2 and more than 90% HbF","correct":false,"visible":false},{"text":"Decreased HbA, raised HbA2 and HbF","correct":false,"visible":false},{"text":"Normal HbA and increased HbF","correct":false,"visible":false},{"text":"HbA absent, HbA2 normal or high or low, HbF markedly increased","correct":true,"visible":false}]},{"id":736,"text":"A 5-day-old baby born after a healthy, full-term pregnancy started bleeding into his genitals. His mother took anti-epileptic drugs throughout her pregnancy. What is the likely cause of the bleeding disorder in this infant?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 638.","responses":[{"text":"Alcohol abuse","correct":false,"visible":false},{"text":"Long-term phenobarbital","correct":true,"visible":false},{"text":"Congenital leukemia","correct":false,"visible":false},{"text":"Vitamin K deficiency","correct":false,"visible":false},{"text":"Poisoning","correct":false,"visible":false}]},{"id":738,"text":"In which one of the following scenarios is vitamin K given?","explanation":null,"reference":"Clarke D, Pillay Y, Anderson F, Thomson S. The current standard of care in the periprocedural management of the patient with obstructive jaundice. Annals of The Royal College of Surgeons of England. Published November 2006. Accessed April 9, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC1963825/","responses":[{"text":"Peptic ulcer","correct":false,"visible":false},{"text":"Worm infection","correct":false,"visible":false},{"text":"Obstructive jaundice","correct":true,"visible":false},{"text":"Heparin","correct":false,"visible":false},{"text":"Colonic polyp","correct":false,"visible":false}]},{"id":739,"text":"Which of the following is donor blood screened for before a transfusion?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 930.","responses":[{"text":"Parasitic infection","correct":false,"visible":false},{"text":"Viral infection","correct":true,"visible":false},{"text":"Bacterial infection","correct":false,"visible":false},{"text":"Fungal infection","correct":false,"visible":false},{"text":"Protozoal infection","correct":false,"visible":false}]},{"id":746,"text":"A pregnant woman in her 3rd trimester is diagnosed with iron deficiency anemia. Which of the following type of cells will be found on her blood smear?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 42.","responses":[{"text":"Hypochromic, Microcytic","correct":true,"visible":false},{"text":"Hypochromic, Normocytic","correct":false,"visible":false},{"text":"Hypochromic, Normocytic","correct":false,"visible":false},{"text":"Hyperchromic, Normocytic","correct":false,"visible":false},{"text":"Hyperchromic, Macrocytic","correct":false,"visible":false}]},{"id":749,"text":"Which of the following statements about Hodgkin lymphoma is correct?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 62.","responses":[{"text":"Negative for CD15 and CD30","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Mixed cellularity is the most commonly found Hodgkin lymphoma","correct":false,"visible":false},{"text":"Painful enlargement of lymph nodes","correct":false,"visible":false},{"text":"Presence of Reed sternberg cells","correct":true,"visible":false}]},{"id":751,"text":"Which of the following lymphomas is involved in the Epstein-Barr virus (EBV) infection?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 224.","responses":[{"text":"Multiple myeloma","correct":false,"visible":false},{"text":"Burkitt lymphoma","correct":true,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Kaposi's sarcoma","correct":false,"visible":false},{"text":"Diffuse large B-cell lymphoma","correct":false,"visible":false}]},{"id":755,"text":"A child suffering from hemolytic uremic syndrome will have which one of the following finding in his peripheral blood smear?","explanation":"In cases of **Hemolytic Uremic Syndrome (HUS)**, a condition characterized by the triad of microangiopathic hemolytic anemia, thrombocytopenia, and acute kidney injury, a peripheral blood smear typically shows the presence of **schistocytes**.\r\n\r\nSchistocytes are fragmented red blood cells that result from mechanical damage to erythrocytes as they pass through small blood vessels obstructed by platelet clumps or fibrin strands. In HUS, the formation of microthrombi in small blood vessels, particularly in the kidneys, leads to the shearing and fragmentation of red blood cells, resulting in the presence of schistocytes in the peripheral blood smear.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 33.","responses":[{"text":"Schistocytes","correct":true,"visible":false},{"text":"Howell-jolly bodies","correct":false,"visible":false},{"text":"Target cells","correct":false,"visible":false},{"text":"Tear drop RBCs","correct":false,"visible":false},{"text":"Aur rods","correct":false,"visible":false}]},{"id":760,"text":"A 5-month-old child presented with bleeding from the genitals. His maternal uncle had a history of prolonged bleeding. What will be the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 34.","responses":[{"text":"Hemophilia","correct":true,"visible":false},{"text":"von Willebrand disease","correct":false,"visible":false},{"text":"Heparin induced thrombocytopenia","correct":false,"visible":false},{"text":"Disseminated intravascular coagulation","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":765,"text":"Which of the following statements is true about tacrolimus?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 89.","responses":[{"text":"Stimulates T-cell activation","correct":false,"visible":false},{"text":"Calcineurin inhibitor","correct":true,"visible":false},{"text":"IL-2 transcription occurs","correct":false,"visible":false},{"text":"Does not bind to FK506 protein","correct":false,"visible":false},{"text":"Does not cause nephrotoxicity","correct":false,"visible":false}]},{"id":766,"text":"Why is low molecular weight heparin (LMWH) preferred over unfractionated heparin (UFH)?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 278.","responses":[{"text":"LMWH can be taken orally","correct":false,"visible":false},{"text":"LMWH can be given in all conditions","correct":false,"visible":false},{"text":"LMWH has no side effects","correct":false,"visible":false},{"text":"LMWH has longer half life","correct":true,"visible":false},{"text":"LMWH has lesser half life","correct":false,"visible":false}]},{"id":767,"text":"In which one of the following blue granules are most likely to be seen?","explanation":null,"reference":"Paxton S, Peckham M, Knibbs A. The leeds histology guide. Published online 2003. Accessed April 9, 2022. https://www.histology.leeds.ac.uk/blood/blood_wbc.php","responses":[{"text":"Eosinophils","correct":false,"visible":false},{"text":"Lymphocytes","correct":false,"visible":false},{"text":"Basophils","correct":true,"visible":false},{"text":"Monocytes","correct":false,"visible":false},{"text":"Neutrophils","correct":false,"visible":false}]},{"id":768,"text":"Which one of the following cells is present in acute inflammation?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n78.","responses":[{"text":"Neutrophils","correct":true,"visible":false},{"text":"T lymphocytes","correct":false,"visible":false},{"text":"Plasma cells","correct":false,"visible":false},{"text":"Macrophages","correct":false,"visible":false},{"text":"Monocytes","correct":false,"visible":false}]},{"id":769,"text":"What is the most common cause of vitamin B12 deficiency anemia?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 45.","responses":[{"text":"Diphyllobothrium","correct":false,"visible":false},{"text":"Veganism","correct":false,"visible":false},{"text":"Gastrointestinal TB","correct":false,"visible":false},{"text":"Ileal resection","correct":false,"visible":false},{"text":"Pernicious anemia","correct":true,"visible":false}]},{"id":770,"text":"Which of the following is the first immediate sign after death?","explanation":null,"reference":"Awan NR. Principle and Practice Of Forensic Medicine. 2nd ed. Zubair Book Depot; 2018: 132.","responses":[{"text":"Secondary relaxation","correct":false,"visible":false},{"text":"Putrefaction","correct":false,"visible":false},{"text":"Rigor mortis","correct":false,"visible":false},{"text":"Primary relaxation","correct":true,"visible":false},{"text":"Stiffening","correct":false,"visible":false}]},{"id":771,"text":"A guy who shoots himself tends to get instantaneous rigor instead of rigor mortis. Which one of the following statements most likely signifies the difference between the two?","explanation":null,"reference":"1) Awan NR. Principle and Practice Of Forensic Medicine. 2nd ed. Zubair Book Depot; 2018: 135.\r\n\r\n2)  Hematology module; Forensics medicine slides; Topic: Death-1; Sub-topic: Instantaneous rigor mortis (cadaveric spasm).","responses":[{"text":"Instantaneous rigor indicates time of death instead of mode of death","correct":false,"visible":false},{"text":"Muscle contraction is less marked in instantaneous rigor mortis","correct":false,"visible":false},{"text":"Instantaneous rigor mortis is not immediate after the death","correct":false,"visible":false},{"text":"Instantaneous rigor affects all the muscles","correct":false,"visible":false},{"text":"Primary relaxation is absent in instantaneous rigor mortis","correct":true,"visible":false}]},{"id":772,"text":"A dead body is found by a group of people near the station. It is concluded that 6 to 10 hours have passed since the time of death. Which one of the following is most likely to be developed by this time in the body?","explanation":null,"reference":"Subrahmanyam BV. Parikh’s Textbook of Medical Jurisprudence, Forensic Medicine and Toxicology for Classrooms and Courtrooms. 7th ed. CBS Publishers \u0026 Distributors; 2017: 144.","responses":[{"text":"Instantaneous rigor","correct":false,"visible":false},{"text":"Postmortem caloricity","correct":false,"visible":false},{"text":"Potassium increase in CSF","correct":false,"visible":false},{"text":"Rigor mortis","correct":false,"visible":false},{"text":"Postmortem lividity","correct":true,"visible":false}]},{"id":773,"text":"A 52-year-old patient presented to the clinic to get his blood reports examined. He was being investigated following his presentation to the clinic with a history of recurrent infections and easy fatiguability for 6 months. The peripheral film demonstrated peculiar monocytes twice the size of mature lymphocytes with round nuclei, abundant cytoplasm, and circumferential projections. An attempt to perform bone marrow aspiration revealed a dry tap. What is the most likely diagnosis for this patient?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 57.","responses":[{"text":"Hairy cell leukemia","correct":true,"visible":false},{"text":"Acute myeloid leukemia","correct":false,"visible":false},{"text":"Acute lymphoblastic leukemia","correct":false,"visible":false},{"text":"Infectious mononucleosis","correct":false,"visible":false},{"text":"Prolymphocytic leukemia","correct":false,"visible":false}]},{"id":775,"text":"Which of the following factors promotes sickling?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 637.","responses":[{"text":"Bacterial illness","correct":false,"visible":false},{"text":"Hyperoxia","correct":false,"visible":false},{"text":"Alkalosis","correct":false,"visible":false},{"text":"Hypotonicity","correct":false,"visible":false},{"text":"Dehydration","correct":true,"visible":false}]},{"id":798,"text":"Which condition shows both arterial and venous thrombosis?","explanation":null,"reference":null,"responses":[{"text":"Factor V Leiden mutation","correct":false,"visible":false},{"text":"Protein S deficiency","correct":false,"visible":false},{"text":"Antithrombin deficiency","correct":false,"visible":false},{"text":"Protein C deficiency","correct":false,"visible":false},{"text":"Antiphospholipid antibody syndrome","correct":true,"visible":false}]},{"id":814,"text":"A patient presents with chipmunk-like facies and a crew-cut appearance of the skull on X-ray. Laboratory investigations show increased fetal hemoglobin (HbF). What is the most likely underlying cause?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 640.","responses":[{"text":"Beta-thalassemia minor","correct":false,"visible":false},{"text":"Anemia of chronic disease","correct":false,"visible":false},{"text":"Iron deficiency anemia","correct":false,"visible":false},{"text":"Beta-thalassemia major","correct":true,"visible":false},{"text":"Sickle cell anemia","correct":false,"visible":false}]},{"id":835,"text":"A 22-year-old woman attends an antenatal booking appointment. She has had previous 3 miscarriages. She has mouth ulcers and joint pains and is evaluated for arthritis/ arthralgia. Which single pair of results are most likely to confirm the underlying cause of her symptoms?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 480.","responses":[{"text":"Decreased hemoglobin and decreased mean corpuscular volume (MCV)","correct":false,"visible":false},{"text":"Increased activated partial thromboplastin time (aPTT) and decreased platelets","correct":true,"visible":false},{"text":"Decrease hemoglobin and increased reticulocytes","correct":false,"visible":false},{"text":"Increased erythrocyte sedimentation rate (ESR) and rheumatoid factor","correct":false,"visible":false},{"text":"Increased lactate dehydrogenase (LDH) and increased bilirubin","correct":false,"visible":false}]},{"id":860,"text":"A child suffering from beta-thalassemia is most likely to present the clinical features at the age of:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 640.","responses":[{"text":"10 to 12 months after birth","correct":false,"visible":false},{"text":"few months before the birth","correct":false,"visible":false},{"text":"6 to 9 months after birth","correct":true,"visible":false},{"text":"In middle age","correct":false,"visible":false},{"text":"1 year after birth","correct":false,"visible":false}]},{"id":863,"text":"Which one of the following gene products is seen in chronic myelogenous leukemia?","explanation":null,"reference":"1. Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 58.\r\n2. Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 616.","responses":[{"text":"BCL-2","correct":false,"visible":false},{"text":"Heavy chain Ig and BCL-2","correct":false,"visible":false},{"text":"BCR-ABL","correct":true,"visible":false},{"text":"Heavy chain Ig and c-myc","correct":false,"visible":false},{"text":"c-myc","correct":false,"visible":false}]},{"id":864,"text":"Which one of the following diseases is associated with platelet aggregation defect?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 660.","responses":[{"text":"Hemolytic-uremic syndrome","correct":false,"visible":false},{"text":"Glanzmann thrombasthenia","correct":true,"visible":false},{"text":"Thrombotic thrombocytopenic purpura","correct":false,"visible":false},{"text":"Immune thrombocytopenia","correct":false,"visible":false},{"text":"Bernard-Soulier syndrome","correct":false,"visible":false}]},{"id":865,"text":"Which one of the following blood tests is done to detect sickle cell disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 638.","responses":[{"text":"flow cytometry","correct":false,"visible":false},{"text":"Serum protein electrophoresis","correct":false,"visible":false},{"text":"Hemoglobin electrophoresis","correct":true,"visible":false},{"text":"Schilling test","correct":false,"visible":false},{"text":"Osmotic fragility test","correct":false,"visible":false}]},{"id":867,"text":"A person exposed to asbestos is more likely to develop which type of cancer?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 713.","responses":[{"text":"Oropharyngeal carcinoma","correct":false,"visible":false},{"text":"Breast cancer","correct":false,"visible":false},{"text":"Malignant mesothelioma","correct":false,"visible":false},{"text":"Pleural solitary fibrous tumor","correct":false,"visible":false},{"text":"Lung cancer","correct":true,"visible":false}]},{"id":873,"text":"Which of the following drugs does NOT work by inhibiting ADP binding to platelet receptors?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 274.","responses":[{"text":"Abciximab","correct":true,"visible":false},{"text":"Prasugrel","correct":false,"visible":false},{"text":"Ticagrelor","correct":false,"visible":false},{"text":"Ticlopidine","correct":false,"visible":false},{"text":"Clopidogrel","correct":false,"visible":false}]},{"id":874,"text":"Which of the following drugs inhibits only factor Xa?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 281.","responses":[{"text":"Rivaroxiban","correct":true,"visible":false},{"text":"Aspirin","correct":false,"visible":false},{"text":"Unfractionated Heparin","correct":false,"visible":false},{"text":"Bivalirudin","correct":false,"visible":false},{"text":"Argatroban","correct":false,"visible":false}]},{"id":875,"text":"In which of the following conditions is streptokinase contraindicated?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 979.","responses":[{"text":"DIC","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Acute MI","correct":false,"visible":false},{"text":"DVT","correct":false,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false}]},{"id":876,"text":"Which of the following drugs is a platelet aggregating inhibitor?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 272.","responses":[{"text":"Heparin","correct":false,"visible":false},{"text":"Argatroban","correct":false,"visible":false},{"text":"Aspirin","correct":true,"visible":false},{"text":"Warfarin","correct":false,"visible":false},{"text":"Dabigatran","correct":false,"visible":false}]},{"id":877,"text":"Which of the following statements best describe compliance with a drug?","explanation":null,"reference":null,"responses":[{"text":"Doctors and patients needs are fully articulated","correct":true,"visible":false},{"text":"By telling its side effects","correct":false,"visible":false},{"text":"By telling its outcomes","correct":false,"visible":false},{"text":"Give details about the alternative treatments","correct":false,"visible":false},{"text":"By telling the diagnosis to the patient","correct":false,"visible":false}]},{"id":878,"text":"Which of the following set of people are most vulnerable to indoor air pollution?","explanation":null,"reference":"Household air pollution and health. Accessed April 9, 2022. https://www.who.int/news-room/fact-sheets/detail/household-air-pollution-and-health","responses":[{"text":"Middle aged men","correct":false,"visible":false},{"text":"Elderly","correct":false,"visible":false},{"text":"Any aged person","correct":false,"visible":false},{"text":"Women and children","correct":true,"visible":false},{"text":"Pregnant women","correct":false,"visible":false}]},{"id":879,"text":"Through which of the following bones age and sex determination of a skeleton can be determined?","explanation":null,"reference":"Dow Lecture slides, Forensic medicine, Personal Identity III","responses":[{"text":"Ribs","correct":false,"visible":false},{"text":"Radius and ulna","correct":false,"visible":false},{"text":"Vertebrae","correct":false,"visible":false},{"text":"Skull and mandible","correct":true,"visible":false},{"text":"Metacarpals","correct":false,"visible":false}]},{"id":888,"text":"Stage IV of Hodgkin lymphoma has a prognosis of:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 610.","responses":[{"text":"60 to 70 %","correct":true,"visible":false},{"text":"10 to 15 %","correct":false,"visible":false},{"text":"70 to 90 %","correct":false,"visible":false},{"text":"20 to 40 %","correct":false,"visible":false},{"text":"0 to 10 %","correct":false,"visible":false}]},{"id":899,"text":"What is diapedesis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 76.","responses":[{"text":"Attachment of leukocytes to endothelial cells","correct":false,"visible":false},{"text":"Movement of leukocytes into the tissues","correct":false,"visible":false},{"text":"Recruitment of leukocytes","correct":false,"visible":false},{"text":"Migration of leukocytes through the endothelium","correct":true,"visible":false},{"text":"Leukocytes aggregation","correct":false,"visible":false}]},{"id":902,"text":"Which one of the following tumors is the neoplasm of T helper cells?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 605.","responses":[{"text":"Mantle cell lymphoma","correct":false,"visible":false},{"text":"Marginal zone lymphoma","correct":false,"visible":false},{"text":"Burkitt lymphoma","correct":false,"visible":false},{"text":"Follicular lymphoma","correct":false,"visible":false},{"text":"Sézary syndrome","correct":true,"visible":false}]},{"id":905,"text":"In which of the following condition mean corpuscular volume (MCV) is low?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 652.","responses":[{"text":"Iron deficiency anemia","correct":true,"visible":false},{"text":"Folate deficiency","correct":false,"visible":false},{"text":"Sickle cell anemia","correct":false,"visible":false},{"text":"Vitamin B12 deficiency","correct":false,"visible":false},{"text":"Hereditary spherocytosis","correct":false,"visible":false}]},{"id":907,"text":"Vitamin K deficiency leads to:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 656, 661.","responses":[{"text":"Increased bleeding time","correct":false,"visible":false},{"text":"Increased PT and PTT","correct":true,"visible":false},{"text":"Decreased platelet count","correct":false,"visible":false},{"text":"Increased PT","correct":false,"visible":false},{"text":"Increased PTT","correct":false,"visible":false}]},{"id":913,"text":"Which of the following describes the mode of transmission of hemophilia A?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 662.","responses":[{"text":"Autosomal recessive","correct":false,"visible":false},{"text":"Autosomal dominant","correct":false,"visible":false},{"text":"X-linked recessive","correct":true,"visible":false},{"text":"X- linked dominant","correct":false,"visible":false},{"text":"Mitochondrial disease","correct":false,"visible":false}]},{"id":915,"text":"Which of the following is the best test for disseminated intravascular coagulation (DIC)?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2018: 35.","responses":[{"text":"Increased fibrinogen concentration","correct":false,"visible":false},{"text":"Decreased PT and PTT","correct":false,"visible":false},{"text":"D-dimer","correct":true,"visible":false},{"text":"International normalized ratio (INR)","correct":false,"visible":false},{"text":"Increased coagulation factors","correct":false,"visible":false}]},{"id":922,"text":"Low erythrocyte sedimentation rate (ESR) represents:","explanation":null,"reference":"Tishkowski K, Gupta V. Erythrocyte sedimentation rate. In: StatPearls. StatPearls Publishing; 2022. Accessed April 10, 2022. http://www.ncbi.nlm.nih.gov/books/NBK557485/","responses":[{"text":"Increased hemoglobin","correct":false,"visible":false},{"text":"Increased red blood cell count","correct":false,"visible":false},{"text":"Increased hematocrit","correct":false,"visible":false},{"text":"No rouleaux formation","correct":true,"visible":false},{"text":"Rouleaux formation","correct":false,"visible":false}]},{"id":923,"text":"Heinz bodies in erythrocytes are characteristic features of:","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2018: 50.","responses":[{"text":"Glutathione reductase deficiency","correct":false,"visible":false},{"text":"Glutathione peroxidase deficiency","correct":false,"visible":false},{"text":"G6PD deficiency","correct":true,"visible":false},{"text":"Glucokinase deficiency","correct":false,"visible":false},{"text":"Pyruvate kinase deficiency","correct":false,"visible":false}]},{"id":928,"text":"Which of the following conditions causes the anemia that occurs due to a defect in RBCs' membrane protein?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2018: 47.","responses":[{"text":"Warm immunohemolytic anemia","correct":false,"visible":false},{"text":"Hereditary spherocytosis","correct":true,"visible":false},{"text":"Sickle cell disease","correct":false,"visible":false},{"text":"Paroxysmal nocturnal hemoglobinuria","correct":false,"visible":false},{"text":"Paroxysmal cold hemoglobinuria","correct":false,"visible":false}]},{"id":1000,"text":"Which of the following antibodies would be present in a person having blood group B?","explanation":null,"reference":"Dean L. The ABO Blood Group. National Center for Biotechnology Information (US); 2005. Accessed April 10, 2022. https://www.ncbi.nlm.nih.gov/books/NBK2267/","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Anti Rh antibodies","correct":false,"visible":false},{"text":"IgM and IgG antibodies","correct":false,"visible":false},{"text":"Anti B antibodies","correct":false,"visible":false},{"text":"Anti A antibodies","correct":true,"visible":false}]},{"id":1001,"text":"Which of the following is the side effect of warfarin?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 280.","responses":[{"text":"Ototoxicity","correct":false,"visible":false},{"text":"Neurotoxicity","correct":false,"visible":false},{"text":"Cardiac toxicity","correct":false,"visible":false},{"text":"Myelosuppression","correct":false,"visible":false},{"text":"Severe birth defects","correct":true,"visible":false}]},{"id":1004,"text":"Which one of the following is not a baseline investigation?","explanation":null,"reference":"Gonzaba. What are common hematology tests? | gonzaba medical group. Published February 17, 2018. Accessed April 10, 2022. https://www.gonzaba.com/what-are-common-hematology-tests/","responses":[{"text":"Lipid profile","correct":false,"visible":false},{"text":"Urine DR","correct":false,"visible":false},{"text":"Complete blood count","correct":false,"visible":false},{"text":"Lumbar puncture","correct":true,"visible":false},{"text":"HbA1c","correct":false,"visible":false}]},{"id":1006,"text":"A 5-year-old presents in an outpatient department with a history of fatigue, headache, and dyspnea. On examination, he was found to be having pale conjunctiva. Upon inquiring her mother she reported that she lost her previous child due to hydrops fetalis. Which thalassemia is incompatible with hydrops fetalis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: Page 642.","responses":[{"text":"Mild Alpha thalassemia","correct":false,"visible":false},{"text":"Severe Alpha thalassemia","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Minor Beta thalassemia","correct":false,"visible":false},{"text":"Major Beta thalassemia","correct":false,"visible":false}]},{"id":1008,"text":"Macrocytic cells are the most common findings in megaloblastic anemia. Which of the following statements best describe about its cause?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 645.","responses":[{"text":"Folate deficiency","correct":false,"visible":false},{"text":"Vitamin B12 deficiency","correct":false,"visible":false},{"text":"Vitamin B6 deficiency","correct":false,"visible":false},{"text":"Vitamin B12 and folate deficiency","correct":true,"visible":false},{"text":"Iron deficiency","correct":false,"visible":false}]},{"id":1012,"text":"Which of the following statements describe leukoerythroblastosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2018: 59.","responses":[{"text":"Immature red blood cells and white blood cells","correct":true,"visible":false},{"text":"Thrombocytopenia","correct":false,"visible":false},{"text":"Mature red blood cells and white blood cells","correct":false,"visible":false},{"text":"Increased reticulocytes","correct":false,"visible":false},{"text":"Megakaryocytes","correct":false,"visible":false}]},{"id":1013,"text":"Which of the following condition has microcytic anemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 640.","responses":[{"text":"Sickle cell anemia","correct":false,"visible":false},{"text":"Thalassemia","correct":true,"visible":false},{"text":"Pernicious anemia","correct":false,"visible":false},{"text":"Aplastic anemia","correct":false,"visible":false},{"text":"Hereditary spherocytosis","correct":false,"visible":false}]},{"id":1014,"text":"If a blood smear is taken from a patient having leukoerythroblstosis. What will be the laboratory findings?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2018: 59.","responses":[{"text":"Mature white blood cells","correct":false,"visible":false},{"text":"Anucleate red blood cells","correct":false,"visible":false},{"text":"Immature red blood cells","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Immature red blood cells and white blood cells","correct":true,"visible":false}]},{"id":1016,"text":"Howell-jolly bodies are seen in:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 636.","responses":[{"text":"G6PD deficiency","correct":false,"visible":false},{"text":"Liver disease","correct":false,"visible":false},{"text":"Aplastic anemia","correct":false,"visible":false},{"text":"Post splenectomy","correct":true,"visible":false},{"text":"Myelodysplastic syndrome","correct":false,"visible":false},{"text":"Sideroblastic anemia","correct":false,"visible":false}]},{"id":1021,"text":"A baby undergoes circumcision and after the procedure the bleeding is prolonged. Upon inquiry, his brothers and sisters have had the same problem. What test should be done for the assessment?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 656.","responses":[{"text":"Thrombin time","correct":false,"visible":false},{"text":"Acute partial thromboplastin time","correct":true,"visible":false},{"text":"Prothrombin time","correct":false,"visible":false},{"text":"Platelet count","correct":false,"visible":false},{"text":"Bleeding time","correct":false,"visible":false}]},{"id":1025,"text":"What will be the risk of inheritance of X-linked disease in the male child if the mother is a carrier and the father is genotypically normal?","explanation":null,"reference":"Basta M, Pandya AM. Genetics, x-linked inheritance. In: StatPearls. StatPearls Publishing; 2022. Accessed April 11, 2022. http://www.ncbi.nlm.nih.gov/books/NBK557383/","responses":[{"text":"25%","correct":false,"visible":false},{"text":"75%","correct":false,"visible":false},{"text":"0%","correct":false,"visible":false},{"text":"50%","correct":true,"visible":false},{"text":"100%","correct":false,"visible":false}]},{"id":1026,"text":"The extrinsic pathway of coagulation is initiated by which of the following?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 919.","responses":[{"text":"Complement system","correct":false,"visible":false},{"text":"Antibodies","correct":false,"visible":false},{"text":"Tissue thromboplastin factor","correct":true,"visible":false},{"text":"Vasoconstriction of venules","correct":false,"visible":false},{"text":"Subendothelial collagen","correct":false,"visible":false}]},{"id":1029,"text":"Which of the following is the most common cause of disseminated intravascular coagulation?","explanation":null,"reference":"1. Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2018:  35.\r\n2. Venugopal A. Disseminated intravascular coagulation. Indian J Anaesth. 2014;58(5):603-608. doi:10.4103/0019-5049.144666","responses":[{"text":"Bacterial sepsis","correct":true,"visible":false},{"text":"Malignancy","correct":false,"visible":false},{"text":"Hypovolemic shock","correct":false,"visible":false},{"text":"Massive trauma","correct":false,"visible":false},{"text":"Acute pancreatitis","correct":false,"visible":false}]},{"id":1030,"text":"Which of the following drug causes cardiac toxicity?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 464.","responses":[{"text":"Dactinomycin","correct":false,"visible":false},{"text":"Bleomycin","correct":false,"visible":false},{"text":"Doxorubicin","correct":true,"visible":false},{"text":"Warfarin","correct":false,"visible":false},{"text":"Heparin","correct":false,"visible":false}]},{"id":1033,"text":"Hemoglobinuria is a feature of which of the following?","explanation":null,"reference":"Barber BE, Grigg MJ, William T, Yeo TW, Anstey NM. Intravascular hemolysis with hemoglobinuria in a splenectomized patient with severe Plasmodium knowlesi malaria. Malar J. 2016;15(1):462. doi:10.1186/s12936-016-1514-0","responses":[{"text":"Thalassemia","correct":false,"visible":false},{"text":"Anemia of chronic disease","correct":false,"visible":false},{"text":"Intravascular hemolysis","correct":true,"visible":false},{"text":"Iron deficiency anemia","correct":false,"visible":false},{"text":"Extravascular hemolysis","correct":false,"visible":false}]},{"id":1036,"text":"Monocytosis is seen in which of the following situations?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 584.","responses":[{"text":"Acute myeloid leukemia","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Tuberculosis","correct":true,"visible":false},{"text":"Polycythemia vera","correct":false,"visible":false},{"text":"Wilsons disease","correct":false,"visible":false}]},{"id":1037,"text":"Which of the following is the feature of chronic hemolytic anemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 631.","responses":[{"text":"Loss of ferritin","correct":false,"visible":false},{"text":"Increased transferrin","correct":false,"visible":false},{"text":"Hemosiderinuria","correct":true,"visible":false},{"text":"Loss of iron","correct":false,"visible":false},{"text":"Hemoglobinemia","correct":false,"visible":false}]},{"id":1038,"text":"Which of the following is given to a patient suffering from hemophilia A?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 663.","responses":[{"text":"Recombinant factor 8","correct":true,"visible":false},{"text":"Corticosteroid's","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Penicillin","correct":false,"visible":false},{"text":"Plasmapheresis","correct":false,"visible":false}]},{"id":1040,"text":"Which of the following substances are required for effective iron absorption?","explanation":null,"reference":"Lynch SR, Cook JD. Interaction of vitamin C and iron. Ann N Y Acad Sci. 1980;355:32-44. doi:10.1111/j.1749-6632.1980.tb21325.x\r\nhttps://pubmed.ncbi.nlm.nih.gov/6940487/","responses":[{"text":"Folic acid","correct":false,"visible":false},{"text":"Ascorbic acid","correct":true,"visible":false},{"text":"Zinc","correct":false,"visible":false},{"text":"Calcium","correct":false,"visible":false},{"text":"Magnesium","correct":false,"visible":false}]},{"id":1041,"text":"Which of the following statement is not true about acute lymphoblastic leukemia (ALL)?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 590.","responses":[{"text":"B-ALL is more common than T-ALL","correct":false,"visible":false},{"text":"Can be B-ALL or T-ALL","correct":false,"visible":false},{"text":"Most common cancer of children","correct":false,"visible":false},{"text":"No blast cell seen in both marrow and periphery","correct":true,"visible":false},{"text":"Has \u003e20% blast cells","correct":false,"visible":false}]},{"id":1043,"text":"Which one of the following is the feature of aplastic anemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 654.","responses":[{"text":"Reticulocytopenia","correct":true,"visible":false},{"text":"Hypercellular bone marrow","correct":false,"visible":false},{"text":"Reticulocytosis","correct":false,"visible":false},{"text":"Increased myeloid cells","correct":false,"visible":false},{"text":"Polycythemia","correct":false,"visible":false}]},{"id":1046,"text":"A 10-year-old child who is otherwise healthy got a complete blood count done which showed Hb of 10 gm/dL, with hypochromic and microcytic red cell indices. Her pediatrician is assuming her to be a carrier of the beta-thalassemia trait. Which of the following tests will confirm her diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 44.","responses":[{"text":"Schilling test","correct":false,"visible":false},{"text":"Hemoglobin electrophoresis","correct":true,"visible":false},{"text":"Osmotic fragility test","correct":false,"visible":false},{"text":"Blood culture","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":1055,"text":"Which of the following antibodies are present in Bernard-Soulier syndrome?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 434.","responses":[{"text":"Glycoprotein Ib antibodies","correct":true,"visible":false},{"text":"Glycoprotein IIa/IIIb antibodies","correct":false,"visible":false},{"text":"Glycoprotein Ib/IIIb antibodies","correct":false,"visible":false},{"text":"Platelet membrane phospholipids","correct":false,"visible":false},{"text":"Glycoprotein IIa","correct":false,"visible":false}]},{"id":1057,"text":"Which of the following drugs is not used in the treatment of iron deficiency anemia?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 566.","responses":[{"text":"Ferrous gluconate","correct":false,"visible":false},{"text":"Folic acid","correct":true,"visible":false},{"text":"Ferrous fumarate","correct":false,"visible":false},{"text":"Carbonyl iron","correct":false,"visible":false},{"text":"Ferrous sulfate","correct":false,"visible":false}]},{"id":1087,"text":"When is brain death declared?","explanation":null,"reference":"Starr R, Tadi P, Pfleghaar N. Brain death. In: StatPearls. StatPearls Publishing; 2022. Accessed April 11, 2022. http://www.ncbi.nlm.nih.gov/books/NBK538159/","responses":[{"text":"When there is no pulse","correct":false,"visible":false},{"text":"When person stops breathing","correct":false,"visible":false},{"text":"When there is no proper circulation","correct":false,"visible":false},{"text":"When there is loss of brainstem reflexes","correct":true,"visible":false},{"text":"When there is no oxygen delivery","correct":false,"visible":false}]},{"id":1088,"text":"Which of the following results in sickle cell crisis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 638.","responses":[{"text":"Vaso-occlusive crisis","correct":true,"visible":false},{"text":"Sickling","correct":false,"visible":false},{"text":"Autosplenectomy","correct":false,"visible":false},{"text":"Aplastic crisis","correct":false,"visible":false},{"text":"Sequestration crisis","correct":false,"visible":false}]},{"id":1089,"text":"Which of the following is the most feared complication in sickle cell disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 637.","responses":[{"text":"Auto-splenectomy","correct":false,"visible":false},{"text":"Osteomyelitis","correct":false,"visible":false},{"text":"Sequestration crisis","correct":false,"visible":false},{"text":"Dactylitis","correct":false,"visible":false},{"text":"Acute chest syndrome","correct":true,"visible":false}]},{"id":1090,"text":"Which of the following term is used for skin bleeding, which is greater than 3 mm but less than 1 cm?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2018: 31.","responses":[{"text":"Purpura","correct":true,"visible":false},{"text":"Hemarthrosis","correct":false,"visible":false},{"text":"Epistaxis","correct":false,"visible":false},{"text":"Ecchymoses","correct":false,"visible":false},{"text":"Petechiae","correct":false,"visible":false}]},{"id":1094,"text":"Which of the following are indications of death?","explanation":null,"reference":"Dow Lecture Slides'24:Heamtology module, Forensic medicine, Topic: Death, Sub-topic: Present criteria to diagnose death.","responses":[{"text":"Normal electrocardiogram (ECG)","correct":false,"visible":false},{"text":"Normal electroencephalogram (EEG)","correct":false,"visible":false},{"text":"Stop breathing after an hour","correct":false,"visible":false},{"text":"Flat electroencephalogram (EEG), flat electrocardiogram (ECG), stop breathing within 5 minutes","correct":true,"visible":false},{"text":"Weak pulse","correct":false,"visible":false}]},{"id":1095,"text":"Which of the following is the most common cause of death in sickle cell disease?","explanation":null,"reference":null,"responses":[{"text":"Auto-splenectomy","correct":false,"visible":false},{"text":"Aplastic crisis","correct":false,"visible":false},{"text":"Dactylitis","correct":false,"visible":false},{"text":"Acute Chest Syndrome","correct":true,"visible":false},{"text":"Sequestration crisis","correct":false,"visible":false}]},{"id":1096,"text":"A middle-aged man presents with excessive bleeding after a minor cut in the OPD. On examination, his lab results showed increased bleeding time but normal prothrombin time (PT) and partial thromboplastin time (PTT). His lab work also showed increased megakaryocytes with no other abnormality in other myeloid lineages. Which of the following condition is most likely present in the patient?","explanation":null,"reference":null,"responses":[{"text":"Thrombocytosis","correct":false,"visible":false},{"text":"Thrombocytopenia","correct":true,"visible":false},{"text":"Leukopenia","correct":false,"visible":false},{"text":"Leukocytosis","correct":false,"visible":false},{"text":"Polycythemia","correct":false,"visible":false}]},{"id":1097,"text":"Which of the following statement represents asphyxial death?","explanation":null,"reference":null,"responses":[{"text":"Petechiae and congestion","correct":false,"visible":false},{"text":"Bluish face, congested conjunctiva, and petechial hemorrhage","correct":true,"visible":false},{"text":"Cyanosis only","correct":false,"visible":false},{"text":"Petechiae only","correct":false,"visible":false},{"text":"No petechiae","correct":false,"visible":false}]},{"id":1098,"text":"Which of the following statement represents mean corpuscular hemoglobin (MCH)?","explanation":null,"reference":null,"responses":[{"text":"Average mass of WBCs","correct":false,"visible":false},{"text":"Average mass of hemoglobin in one RBC","correct":true,"visible":false},{"text":"Average volume of one RBC","correct":false,"visible":false},{"text":"Average mass of hemoglobin in RBCs","correct":false,"visible":false},{"text":"Average volume of RBCs","correct":false,"visible":false}]},{"id":1099,"text":"In which situation the claim of abortion can be false?","explanation":null,"reference":null,"responses":[{"text":"Menopausal stage","correct":true,"visible":false},{"text":"Multiparous woman","correct":false,"visible":false},{"text":"Girl in her puberty stage","correct":false,"visible":false},{"text":"Women in her mid 30s","correct":false,"visible":false},{"text":"Woman who just crossed her 20s","correct":false,"visible":false}]},{"id":1100,"text":"Which of the following is not a platelet inhibitor?","explanation":null,"reference":null,"responses":[{"text":"Aspirin","correct":false,"visible":false},{"text":"Abciximab","correct":false,"visible":false},{"text":"Acetaminophen","correct":true,"visible":false},{"text":"Clopidogrel","correct":false,"visible":false},{"text":"Ticlopidine","correct":false,"visible":false}]},{"id":1101,"text":"Anti-malarial drugs cause hemolysis in which of the following disease?","explanation":null,"reference":null,"responses":[{"text":"Aplastic anemia","correct":false,"visible":false},{"text":"Myelodysplastic syndrome","correct":false,"visible":false},{"text":"Acute lymphocytic leukemia","correct":false,"visible":false},{"text":"Thalassemia","correct":false,"visible":false},{"text":"Glucose-6-phosphate dehydrogenase deficiency","correct":true,"visible":false}]},{"id":1102,"text":"A 50-year-old man came to an outpatient department with the complaint of having a rash immediately after taking a shower. Which of the following describes his symptoms?","explanation":null,"reference":null,"responses":[{"text":"Multiple myeloma","correct":false,"visible":false},{"text":"Polycythemia Vera","correct":true,"visible":false},{"text":"Gaisbocks syndrome","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Acute lymphoblastic leukemia","correct":false,"visible":false}]},{"id":1103,"text":"Henoch-Schonlein purpura is caused by systemic deposition of:","explanation":null,"reference":null,"responses":[{"text":"Histamine","correct":false,"visible":false},{"text":"Immune complexes","correct":true,"visible":false},{"text":"Epitheloid cells","correct":false,"visible":false},{"text":"Heparin","correct":false,"visible":false},{"text":"Lymphocytes","correct":false,"visible":false}]},{"id":1104,"text":"Which of the following does not happen in platelet disorders?","explanation":null,"reference":null,"responses":[{"text":"Ecchymoses","correct":false,"visible":false},{"text":"Petechiae","correct":false,"visible":false},{"text":"Hemarthrosis","correct":true,"visible":false},{"text":"Mucosal bleeding","correct":false,"visible":false},{"text":"Thrombocytopenia","correct":false,"visible":false}]},{"id":1105,"text":"Myelodysplastic syndrome is NOT characterized by which of the following?","explanation":null,"reference":null,"responses":[{"text":"Ineffective lymphopoiesis","correct":true,"visible":false},{"text":"Heterogenous clonal stem cell disorder","correct":false,"visible":false},{"text":"Occurs in elderly","correct":false,"visible":false},{"text":"Ineffective hematopoiesis","correct":false,"visible":false},{"text":"Anemia, neutropenia and thrombocytopenia","correct":false,"visible":false}]},{"id":1106,"text":"In which of the following condition, alteplase is given?","explanation":null,"reference":null,"responses":[{"text":"Prevention of stroke","correct":false,"visible":false},{"text":"Normal bleeding and coagulation time","correct":false,"visible":false},{"text":"Coronary stenting","correct":false,"visible":false},{"text":"Acute ischemic stroke","correct":true,"visible":false},{"text":"Vasodilation","correct":false,"visible":false}]},{"id":1108,"text":"A cord blood sample of an Rh-ve mother was sent for laboratory testing during labor. Which of the following would indicate the need for blood exchange transfusion?","explanation":null,"reference":"Goljan EF. Rapid Review Pathology. 5th ed. Elsevier, Inc; 2019: 416.","responses":[{"text":"Reticulocyte is corrected to 7%","correct":true,"visible":false},{"text":"Hemoglobin = 10 mg/dL","correct":false,"visible":false},{"text":"Indirect coombs test is weakly negative","correct":false,"visible":false},{"text":"Peripheral cells shows spherocytes","correct":false,"visible":false},{"text":"Serum bilirubin = 2.5 mg/dL","correct":false,"visible":false}]},{"id":1112,"text":"Which of the following factors does NOT  promote the sickling of red blood cells?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 637.","responses":[{"text":"Obesity","correct":true,"visible":false},{"text":"Viral infection","correct":false,"visible":false},{"text":"Acidosis","correct":false,"visible":false},{"text":"Hypoxia","correct":false,"visible":false},{"text":"Dehydration","correct":false,"visible":false}]},{"id":1114,"text":"Which of the following is not classified as a platelet functional disorder?","explanation":null,"reference":null,"responses":[{"text":"Bernard soulier syndrome","correct":false,"visible":false},{"text":"Glanzmann thrombasthemia","correct":false,"visible":false},{"text":"Grey platelet syndrome","correct":false,"visible":false},{"text":"Von Willebrand disease","correct":false,"visible":false},{"text":"Thrombotic thrombocytopenia purpura","correct":true,"visible":false}]},{"id":1116,"text":"How is alteplase formed?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 283.","responses":[{"text":"Made by bacteria in the colon","correct":false,"visible":false},{"text":"Derived from animal sources","correct":false,"visible":false},{"text":"It is naturally found","correct":false,"visible":false},{"text":"Recombinant DNA technology","correct":true,"visible":false},{"text":"Dervied from plant sources","correct":false,"visible":false}]},{"id":1118,"text":"Increased homocysteine levels result in?","explanation":null,"reference":null,"responses":[{"text":"Nephrotoxicity","correct":false,"visible":false},{"text":"Ototoxicity","correct":false,"visible":false},{"text":"Osteonecrosis","correct":false,"visible":false},{"text":"Atherosclerosis","correct":true,"visible":false},{"text":"Cataract","correct":false,"visible":false}]},{"id":1122,"text":"A 14-year-old boy comes to the outpatient department (OPD) with a complaint of weakness and fever for the past few weeks. On examination, there was increased leukocyte count with normal red blood cell and platelet count. His chest CT further showed a mediastinal mass. Which of the following is the most likely condition from which the boy is suffering from?","explanation":null,"reference":null,"responses":[{"text":"Hairy cell leukemia","correct":false,"visible":false},{"text":"Acute lymphoblastic leukemia","correct":true,"visible":false},{"text":"Chronic myelogenous leukemia","correct":false,"visible":false},{"text":"Chronic lymphoblastic leukemia","correct":false,"visible":false},{"text":"Acute myelogenous leukemia","correct":false,"visible":false}]},{"id":1123,"text":"Which of the following statements is true about heparin?","explanation":null,"reference":null,"responses":[{"text":"Doesn't binds to antithrombin III","correct":false,"visible":false},{"text":"Antidote is vitamin K","correct":false,"visible":false},{"text":"Is antiplatelet drug","correct":false,"visible":false},{"text":"Teratogenic","correct":false,"visible":false},{"text":"Can be given in pregnancy","correct":true,"visible":false}]},{"id":1124,"text":"Which of the following is the most common clinical manifestation in Von Willebrand's disease?","explanation":null,"reference":null,"responses":[{"text":"Gum bleeding","correct":true,"visible":false},{"text":"Joint bleeding","correct":false,"visible":false},{"text":"Deep tissue bleeding","correct":false,"visible":false},{"text":"Rectal bleeding","correct":false,"visible":false},{"text":"Post surgical bleeding","correct":false,"visible":false}]},{"id":1126,"text":"The triad of symptoms, thrombocytopenia, acute kidney injury and microangiopathic hemolytic anemia, is seen in which of the following condition?","explanation":null,"reference":null,"responses":[{"text":"Hemolytic-uremic syndrome","correct":true,"visible":false},{"text":"Glanzmann thrombasthenia","correct":false,"visible":false},{"text":"Bernard-Soulier syndrome","correct":false,"visible":false},{"text":"Immune thrombocytopenia","correct":false,"visible":false},{"text":"Disseminated intravascular coagulation","correct":false,"visible":false}]},{"id":1129,"text":"Which of the following is correct regarding cyclophosphamide?","explanation":null,"reference":null,"responses":[{"text":"Inhibitor of hypoxanthine-guanine phosphoribosyltransferase","correct":false,"visible":false},{"text":"Alkylating agent","correct":true,"visible":false},{"text":"Pyrimidine analog","correct":false,"visible":false},{"text":"Inhibitor of dihydrofolate reductase","correct":false,"visible":false},{"text":"IL-2 inhibitor","correct":false,"visible":false}]},{"id":1131,"text":"Which of the following statements is true about fibrinolytics?","explanation":null,"reference":"(1) Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 283. \r\n(2) Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 289.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"They cause allergy and antibody production","correct":true,"visible":false},{"text":"Urokinase directly inhibits plasminogen","correct":false,"visible":false},{"text":"Streptokinase directly inhibits plasminogen","correct":false,"visible":false},{"text":"Contraindicated in acute myocardial infarction","correct":false,"visible":false}]},{"id":1135,"text":"Which of the following condition presents with the usage of platelets and the coagulation factors, along with microangiopathic hemolytic anemia?","explanation":null,"reference":null,"responses":[{"text":"Bernard-Soulier syndrome","correct":false,"visible":false},{"text":"Immune thrombocytopenia","correct":false,"visible":false},{"text":"Glanzmann thrombasthenia","correct":false,"visible":false},{"text":"hemolytic-uremic syndrome","correct":false,"visible":false},{"text":"Disseminated intravascular coagulation","correct":true,"visible":false}]},{"id":1136,"text":"A 20-year-old man whose femur got fractured in a road traffic accident is bleeding profusely from the fracture site. What should he be transfused with?","explanation":null,"reference":null,"responses":[{"text":"Packed red cell concentrate","correct":false,"visible":false},{"text":"Fresh frozen plasma","correct":false,"visible":false},{"text":"Whole blood","correct":true,"visible":false},{"text":"Cryoprecipitate","correct":false,"visible":false},{"text":"Pooled platelets","correct":false,"visible":false}]},{"id":1137,"text":"A 20-year-old man is brought into the emergency after a road traffic accident. As a result, he is suspected to be infected by tetanus. Which of the following vaccine will be given to this man?","explanation":null,"reference":null,"responses":[{"text":"Live attenuated","correct":false,"visible":false},{"text":"Toxoid and immunoglobulin","correct":false,"visible":false},{"text":"Immunoglobulin","correct":false,"visible":false},{"text":"Toxoid","correct":true,"visible":false},{"text":"Dead virus","correct":false,"visible":false}]},{"id":1143,"text":"Which of the following best describes the function of interleukins?","explanation":null,"reference":null,"responses":[{"text":"To prevent mucosal bleeding","correct":false,"visible":false},{"text":"Rolling of white blood cells","correct":false,"visible":false},{"text":"Vasodilation of arterioles","correct":false,"visible":false},{"text":"Diapedesis","correct":false,"visible":false},{"text":"Chemotaxis","correct":true,"visible":false}]},{"id":1146,"text":"Which of the following would the 2nd line treatment for a patient suffering from sickle cell anemia?","explanation":null,"reference":null,"responses":[{"text":"Corticosteroids","correct":false,"visible":false},{"text":"IV vancomycin","correct":false,"visible":false},{"text":"Plasmapheresis","correct":false,"visible":false},{"text":"Hydroxyurea","correct":true,"visible":false},{"text":"Desmopressin","correct":false,"visible":false}]},{"id":1147,"text":"Extramedullary hematopoiesis occurs due to myelodysplastic fibrosis. Which of the following would be the most common site of extramedullary hematopoiesis?","explanation":null,"reference":null,"responses":[{"text":"Spleen","correct":true,"visible":false},{"text":"Thymus","correct":false,"visible":false},{"text":"Bones","correct":false,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Thyroid","correct":false,"visible":false}]},{"id":1149,"text":"Spherocytosis is seen in which other conditions than hereditary spherocytosis?","explanation":null,"reference":null,"responses":[{"text":"Infection-induced hemolytic anemia","correct":true,"visible":false},{"text":"Autosplenectomy","correct":false,"visible":false},{"text":"Thalassemia","correct":false,"visible":false},{"text":"Glucose-6-phosphate dehydrogenase deficiency","correct":false,"visible":false},{"text":"Sideroblastic anemia","correct":false,"visible":false}]},{"id":1150,"text":"A 40-year-old man undergoes successful surgery. On the second postoperative day, he developed a high-grade fever. It was later found out that the doctors had inadvertently left a swab in his abdomen. Which type of negligence is this?","explanation":null,"reference":null,"responses":[{"text":"Civil negligence","correct":false,"visible":false},{"text":"Contributory negligence","correct":false,"visible":false},{"text":"Corporate negligence","correct":false,"visible":false},{"text":"Res-Ipsa-Loquotar","correct":false,"visible":false},{"text":"Criminal negligence","correct":true,"visible":false}]},{"id":1151,"text":"A 50-year-old man visits a medical center with complaints of dyspnea and fatigue. On examination, he was found to have generalized lymphadenopathy and jaundice. His blood smear showed smudge cells. Which of the following is a complication if a patient suffering is from Chronic lymphocytic leukemia?","explanation":null,"reference":null,"responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Autoimmune hemolytic anemia","correct":true,"visible":false},{"text":"Pneumonia","correct":false,"visible":false},{"text":"Fever, rash and itchy back","correct":false,"visible":false},{"text":"Hepatosplenomegaly","correct":false,"visible":false}]},{"id":1152,"text":"The administration of a private hospital does not provide quality instruments to the doctors. Which type of negligence is this?","explanation":null,"reference":null,"responses":[{"text":"Criminal negligence","correct":false,"visible":false},{"text":"Corporate negligence","correct":true,"visible":false},{"text":"Res ipsa loquitur","correct":false,"visible":false},{"text":"Contributory negligence","correct":false,"visible":false},{"text":"Civil negligence","correct":false,"visible":false}]},{"id":1153,"text":"What is the World Health Organization's criteria for anemia in infants?","explanation":null,"reference":null,"responses":[{"text":"Hb \u003c 11.0 gm/dL","correct":true,"visible":false},{"text":"Hb \u003c 14.0 gm/dL","correct":false,"visible":false},{"text":"Hb \u003c 12.0 gm/dL","correct":false,"visible":false},{"text":"Hb \u003c 10.0 gm/dL","correct":false,"visible":false},{"text":"Hb \u003c 13.5 gm/dL","correct":false,"visible":false}]},{"id":1154,"text":"How much hemoglobin and hematocrit are increased respectively when one pint of blood is transfused?","explanation":null,"reference":null,"responses":[{"text":"3 mg/dl and 1 %","correct":false,"visible":false},{"text":"0 mg/dl and 2 %","correct":false,"visible":false},{"text":"2 mg/dl and 0 %","correct":false,"visible":false},{"text":"5 mg/dl and 10 %","correct":false,"visible":false},{"text":"1 mg/dl and 3 %","correct":true,"visible":false}]},{"id":1155,"text":"Ringed sideroblasts are seen in which of the following?","explanation":null,"reference":null,"responses":[{"text":"Hereditary spherocytosis","correct":false,"visible":false},{"text":"Aplastic anemia","correct":false,"visible":false},{"text":"Sickle cell anemia","correct":false,"visible":false},{"text":"Sideroblastic anemia","correct":true,"visible":false},{"text":"Myelodysplastic syndrome","correct":false,"visible":false}]},{"id":1156,"text":"The lacunar variant of Reed-Sternberg (RS) cells is found in:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 607.","responses":[{"text":"Mixed cellularity","correct":false,"visible":false},{"text":"Lymphocyte rich","correct":false,"visible":false},{"text":"Lymphocyte depletion","correct":false,"visible":false},{"text":"Lymphocyte predominant","correct":false,"visible":false},{"text":"Nodular sclerosis","correct":true,"visible":false}]},{"id":1164,"text":"A 14-year-old boy presents to the outpatient department (OPD) with weakness and fever. On examination, his bone marrow showed 80% hypercellularity but 3% myeloblasts. Which of the following condition is most likely associated with his symptoms?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 591.","responses":[{"text":"Acute myelogenous leukemia","correct":false,"visible":false},{"text":"Acute lymphoblastic leukemia","correct":true,"visible":false},{"text":"Hairy cell leukemia","correct":false,"visible":false},{"text":"Chronic myelogenous leukemia","correct":false,"visible":false},{"text":"Chronic lymphoblastic leukemia","correct":false,"visible":false}]},{"id":1166,"text":"A man presents to the emergency with weakness. On examination, Reed-Sternberg cells were found along with swelling of a lymph node. There were no systemic symptoms reported. The doctor concluded his condition as Hodgkin lymphoma. What is the stage of lymphoma in this patient?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 962.","responses":[{"text":"Stage IB","correct":false,"visible":false},{"text":"Stage IV","correct":false,"visible":false},{"text":"Stage II","correct":false,"visible":false},{"text":"Stage IA","correct":true,"visible":false},{"text":"Stage III","correct":false,"visible":false}]},{"id":1168,"text":"How is acute leukemia differentiated by chronic leukemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 590.","responses":[{"text":"Presence of blast cells","correct":true,"visible":false},{"text":"Aggressive nature","correct":false,"visible":false},{"text":"Size","correct":false,"visible":false},{"text":"Metastasis","correct":false,"visible":false},{"text":"Location","correct":false,"visible":false}]},{"id":1169,"text":"Which of the following Gustafson's method is most reliable?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 69.","responses":[{"text":"Cement apposition","correct":false,"visible":false},{"text":"Loosening of teeth","correct":false,"visible":false},{"text":"Root transparency","correct":true,"visible":false},{"text":"Root resorption","correct":false,"visible":false},{"text":"Gradual wearing out of teeth","correct":false,"visible":false}]},{"id":1170,"text":"Auer rods in the cytoplasm are a classical finding of which of the following neoplasms?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 613.","responses":[{"text":"Hodgkin Lymphoma","correct":false,"visible":false},{"text":"Chronic myelogenous leukemia (CML)","correct":false,"visible":false},{"text":"Acute lymphoblastic leukemia (ALL)","correct":false,"visible":false},{"text":"Chronic lymphocytic leukemia (CLL)","correct":false,"visible":false},{"text":"Acute myeloid leukemia (AML)","correct":true,"visible":false}]},{"id":1171,"text":"Which of these is not prepared from human blood?","explanation":null,"reference":null,"responses":[{"text":"Cryoprecipitate","correct":false,"visible":false},{"text":"Fresh frozen plasma","correct":false,"visible":false},{"text":"Platelets","correct":false,"visible":false},{"text":"Packed cells","correct":false,"visible":false},{"text":"Recombinant factor VIII","correct":true,"visible":false}]},{"id":1173,"text":"A patient having B-Thalassemia on regular transfusions starts to develop urticaria in the past 4 to 5 months. Which of the following should be given to him before his next transfusion session?","explanation":null,"reference":null,"responses":[{"text":"Antihistamines","correct":true,"visible":false},{"text":"Anti Rh negative antibodies","correct":false,"visible":false},{"text":"Antimalarial","correct":false,"visible":false},{"text":"Washed blood","correct":false,"visible":false},{"text":"Corticosteroids","correct":false,"visible":false}]},{"id":1177,"text":"What is the daily requirement of iron in pregnant females?","explanation":null,"reference":null,"responses":[{"text":"14.7 mg/dl","correct":false,"visible":false},{"text":"0.4 mg/dl","correct":false,"visible":false},{"text":"2 mg/dl","correct":false,"visible":false},{"text":"7 mg/dl","correct":false,"visible":false},{"text":"3.4 mg/dl","correct":true,"visible":false}]},{"id":1178,"text":"A body is found in the jungle resisting to blanch on pressure. How many hours have elapsed after the death of this person?","explanation":null,"reference":"Subrahmanyam BV. Parikh’s Textbook of Medical Jurisprudence, Forensic Medicine and Toxicology for Classrooms and Courtrooms. 8th ed. CBS Publishers; 2019: 120, 154.","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"1 to 3 hours","correct":false,"visible":false},{"text":"24 hours","correct":false,"visible":false},{"text":"10 to 12 hours","correct":true,"visible":false},{"text":"5 to 6 hours","correct":false,"visible":false}]},{"id":1179,"text":"Koilonychia is seen in which of the following conditions?","explanation":null,"reference":null,"responses":[{"text":"Polycythemia","correct":false,"visible":false},{"text":"Neutropenia","correct":false,"visible":false},{"text":"Anemia","correct":true,"visible":false},{"text":"Thrombocytopenia","correct":false,"visible":false},{"text":"Leukocytosis","correct":false,"visible":false}]},{"id":1180,"text":"Which of the following is used as a corrosive used for cleaning rust?","explanation":null,"reference":null,"responses":[{"text":"Aluminum","correct":false,"visible":false},{"text":"Oxalic acid","correct":true,"visible":false},{"text":"Hydrogen peroxide","correct":false,"visible":false},{"text":"Zinc oxide","correct":false,"visible":false},{"text":"Copper","correct":false,"visible":false}]},{"id":1181,"text":"Heparin works in association with which of the following?","explanation":null,"reference":null,"responses":[{"text":"Calmodulin","correct":false,"visible":false},{"text":"Platelets","correct":false,"visible":false},{"text":"Dense proteins","correct":false,"visible":false},{"text":"Warfarin","correct":false,"visible":false},{"text":"Antithrombin III","correct":true,"visible":false}]},{"id":1182,"text":"Which of the following statements best describes neoadjuvant chemotherapy?","explanation":null,"reference":null,"responses":[{"text":"Chemotherapy given during surgery","correct":false,"visible":false},{"text":"Chemotherapy given as a supplemental treatment after surgery or radiation","correct":false,"visible":false},{"text":"Chemotherapy given in low doses to prolong remission","correct":false,"visible":false},{"text":"Chemotherapy given as a supplemental treatment during radiation","correct":false,"visible":false},{"text":"Chemotherapy given prior to surgery in an attempt to shrink the tumor","correct":true,"visible":false}]},{"id":1183,"text":"Which of the following is NOT the most common complication of chemotherapy?","explanation":null,"reference":null,"responses":[{"text":"Vomiting","correct":false,"visible":false},{"text":"Alopecia","correct":false,"visible":false},{"text":"Bladder cancer","correct":true,"visible":false},{"text":"Stomatitis","correct":false,"visible":false},{"text":"Myelosuppression","correct":false,"visible":false}]},{"id":1184,"text":"The postmortem sign of 'cattle trucking' is seen in which organ?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 137.","responses":[{"text":"Cornea","correct":false,"visible":false},{"text":"Brain","correct":false,"visible":false},{"text":"Heart","correct":false,"visible":false},{"text":"Retina","correct":true,"visible":false},{"text":"Limbs","correct":false,"visible":false}]},{"id":1185,"text":"Which of the following is associated with thalassemia disease?","explanation":null,"reference":null,"responses":[{"text":"Defective globin chains","correct":false,"visible":false},{"text":"Thrombocytopenia","correct":false,"visible":false},{"text":"Leukocytosis","correct":false,"visible":false},{"text":"Thrombocytosis","correct":false,"visible":false},{"text":"Deficient globin chains","correct":true,"visible":false}]},{"id":1186,"text":"A man presents to the emergency with tenderness on his left upper quadrant and yellow discoloration of the skin.  On examination, he is found to have icterus and splenomegaly. His lab results show increased total bilirubin levels but normal direct bilirubin. His blood smear further show an increased number of reticulocytes. Which of the following is the most likely reason for this?","explanation":null,"reference":null,"responses":[{"text":"Thromocytopenia","correct":false,"visible":false},{"text":"Polycythemia","correct":false,"visible":false},{"text":"Leukemia","correct":false,"visible":false},{"text":"Hemolysis","correct":true,"visible":false},{"text":"Lymphoma","correct":false,"visible":false}]},{"id":1187,"text":"A baby is born to a full-term mother through vaginal delivery. He has tortuous and dilated veins that are widely distributed on his skin and mucous membranes. Which of the following is the most likely condition that the baby is suffering from?","explanation":null,"reference":null,"responses":[{"text":"Sickle cell disease","correct":false,"visible":false},{"text":"Immune thrombocytopenic purpura (ITP)","correct":false,"visible":false},{"text":"Hereditary spherocytosis","correct":false,"visible":false},{"text":"Hereditary hemorrhagic telangiectasia","correct":true,"visible":false},{"text":"Varicose veins","correct":false,"visible":false}]},{"id":1197,"text":"What is the diagnostic test for Hodgkin lymphoma?","explanation":null,"reference":null,"responses":[{"text":"The site of lymph node involved","correct":false,"visible":false},{"text":"Fine Needle Aspiration Cytology (FNAC)","correct":false,"visible":false},{"text":"Checking tenderness of the lymph nodes","correct":false,"visible":false},{"text":"Excision biopsy with histopathology","correct":true,"visible":false},{"text":"Biopsy only","correct":false,"visible":false}]},{"id":1198,"text":"Which one of the following is the surest method of identification?","explanation":null,"reference":null,"responses":[{"text":"Blood group","correct":false,"visible":false},{"text":"Sex","correct":false,"visible":false},{"text":"Belongings","correct":false,"visible":false},{"text":"Age","correct":false,"visible":false},{"text":"Fingerprinting","correct":true,"visible":false}]},{"id":1199,"text":"If a lady had a missed abortion, which of the following is the most suitable transfusion for her?","explanation":null,"reference":null,"responses":[{"text":"Cryoprecipitate","correct":false,"visible":false},{"text":"Platelets and packed red blood cells","correct":false,"visible":false},{"text":"Fresh frozen plasma","correct":false,"visible":false},{"text":"Only platelets","correct":false,"visible":false},{"text":"Packed red blood cells","correct":true,"visible":false}]},{"id":3566,"text":"A 13-year-old female presents to the outpatient department (OPD) with on and off menorrhagia, bleeding gums, and petechial rashes. Her laboratory reports show the following results; Hb= 12.5 g/dl, platelet count= 350,000/mm3, activated partial thromboplastin time (aPTT)= 49s (normal: 29-40s). Which of the following could be the likely diagnosis?","explanation":"The likely diagnosis for the 13-year-old female with on and off **menorrhagia, bleeding gums**, and **petechial rashes**, along with an **elevated activated partial thromboplastin time (aPTT)**, is **von Willebrand disease**.\r\n\r\nVon Willebrand disease is a bleeding disorder characterized by a deficiency or dysfunction of **von Willebrand factor (vWF)**, a protein involved in platelet adhesion and clot formation. The symptoms often include mucocutaneous bleeding, such as nosebleeds, easy bruising, heavy or prolonged menstrual bleeding, and bleeding gums.\r\n\r\nIn this case, the normal platelet count and hemoglobin level make iron deficiency anemia less likely as a diagnosis. Anemia of chronic disease is also less likely as it typically presents with lower hemoglobin levels. Immune thrombocytopenic purpura (ITP) typically presents with isolated thrombocytopenia and does not cause prolonged aPTT. Thrombotic microangiopathy usually presents with signs of microvascular thrombosis and associated organ damage, which are not described in this case.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 662.","responses":[{"text":"Anemia of chronic disease","correct":false,"visible":false},{"text":"Iron deficiency anemia","correct":false,"visible":false},{"text":"Immune thrombocytopenic purpura (ITP)","correct":false,"visible":false},{"text":"Thrombotic microangiopathy","correct":false,"visible":false},{"text":"von Willebrand disease","correct":true,"visible":false}]},{"id":4014,"text":"A 5-year-old boy comes to the outpatient department complaining of a painful and swollen knee. On examination, bleeding is seen within the knee joint but with no signs of physical trauma. His mother gives a family history of a maternal uncle who recently died of a bleeding disorder. Investigations show isolated increased APTT. What is the most likely diagnosis?","explanation":"**Hemophilia A** is an X-linked recessive disorder characterized by a deficiency or dysfunction of coagulation factor VIII.\r\n\r\nThe clinical presentation of a painful and swollen joint without a history of physical trauma suggests an intra-articular hemorrhage. Hemophilia A leads to impaired blood clotting, specifically due to a deficiency of factor VIII, which is involved in the intrinsic pathway of coagulation. As a result, patients with hemophilia A are prone to prolonged APTT (activated partial thromboplastin time).\r\n\r\nThe X-linked inheritance pattern explains the family history of a maternal uncle with a bleeding disorder. Hemophilia A predominantly affects males, while females are usually carriers of the disease.\r\n\r\nConfirmatory laboratory tests may include specific assays to measure factor VIII activity or genetic testing to identify mutations in the factor VIII gene.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 662-663.","responses":[{"text":"Von Willebrand disease","correct":false,"visible":false},{"text":"Hemophilia A","correct":true,"visible":false},{"text":"Hemophilia C","correct":false,"visible":false},{"text":"Hemolytic uremic syndrome","correct":false,"visible":false},{"text":"Thrombocytopenia","correct":false,"visible":false}]},{"id":10330,"text":"What is the inheritance pattern of glucose-6-phosphate dehydrogenase (G6PD) deficiency?","explanation":"**G6PD deficiency** is an **X-linked recessive** genetic disorder. This means that the gene responsible for G6PD is located on the X chromosome. Males have one X and one Y chromosome (XY), while females have two X chromosomes (XX).\r\n\r\nMales who inherit one copy of the mutated gene (X-linked recessive allele) from their carrier mother will express the disorder because they have no second X chromosome with a normal copy of the gene to compensate.\r\n\r\nFemales typically do not express the disorder unless they inherit two copies of the mutated gene, one from each carrier parent (homozygous for the X-linked recessive allele). Carrier females with one mutated gene and one normal gene usually do not manifest the condition but can pass it on to their offspring.","reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 432.","responses":[{"text":"X-linked recessive","correct":true,"visible":false},{"text":"Autosomal dominant","correct":false,"visible":false},{"text":"Multifactorial","correct":false,"visible":false},{"text":"Autosomal recessive","correct":false,"visible":false},{"text":"X-linked dominant","correct":false,"visible":false}]},{"id":14229,"text":"A female patient is brought to the clinic after a snake bite with complaints of oozing blood from the wound site, widespread pinpoint and patchy red spots on her skin, and dyspnea. She appears lethargic, has cold skin, and is diaphoretic. She is immediately diagnosed with disseminated intravascular coagulation (DIC) secondary to envenomation by the snake. \r\n\r\nWhich of the following is the most appropriate step in the management of this patient?","explanation":"-Coagulopathy is best reversed by antivenom. With a few exceptions, it should be given intravenously. \r\n-The first step to managing DIC is treating the underlying cause","reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 247.","responses":[{"text":"Oral antivenom","correct":false,"visible":false},{"text":"Packed red blood cells","correct":false,"visible":false},{"text":"Fresh frozen plasma","correct":false,"visible":false},{"text":"Platelets","correct":false,"visible":false},{"text":"Intravenous antivenom","correct":true,"visible":false}]},{"id":14352,"text":"A 55-year-old patient is recovering from non-valvular atrial fibrillation. She is currently on warfarin and esmolol. Her most reason INR level = 7. \r\nWhat is the next best step in the management of this patient?","explanation":null,"reference":null,"responses":[{"text":"Add vitamin K antagonist","correct":false,"visible":false},{"text":"Stop warfarin","correct":true,"visible":false},{"text":"Add heparin","correct":false,"visible":false},{"text":"Add digoxin","correct":false,"visible":false},{"text":"Transfuse fresh frozen plasma","correct":false,"visible":false}]},{"id":14354,"text":"A 50-year-old female presents to the clinic with complaints of hemoptysis and hematuria.  Upon further inquiry, the patient tells you that she was diagnosed with allergic rhinitis when she was 26 years old. Which of the following is the best diagnostic test?","explanation":null,"reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 1044","responses":[{"text":"Serum antineutrophil cytoplasmic antibodies (ANCA)","correct":true,"visible":false},{"text":"Serum antinuclear antibody (ANA)","correct":false,"visible":false},{"text":"ESR and CRP","correct":false,"visible":false},{"text":"Serum anti glomerular basement membrane (anti-GBM) antibodies","correct":false,"visible":false},{"text":"IgM antibodies","correct":false,"visible":false}]},{"id":14356,"text":"A 14-year-old boy presents to the clinic due to excessive bleeding from a wound. He tells you that he often gets bruises, especially on his knees and elbows. This patient most likely has a deficiency of factor VIII. What is the inheritance pattern of this disease?","explanation":null,"reference":"Robbins Pathologic Basis of Disease, 9th edition, page 662.","responses":[{"text":"Mitochondrial inheritance","correct":false,"visible":false},{"text":"X-linked dominant inheritance","correct":false,"visible":false},{"text":"Autosomal recessive","correct":false,"visible":false},{"text":"Autosomal dominant","correct":false,"visible":false},{"text":"X-linked recessive","correct":true,"visible":false}]},{"id":14371,"text":"A 71-year-old male presents to the clinic with complaints of unintentional weight loss, recurrent infections, lethargy, and night sweats. On examination, he has painless cervical and supraclavicular lymph node enlargements and the liver border can be palpated 1cm below the costal margin. \r\nLaboratory investigations show WBC = 15000 cells/mm3, lymphocytes = 8000 cells/mm3, Hb = 9 g/dL, blood smear shows a high percentage of small, mature lymphocytes, and the presence of smudge cells. \r\n\r\nWhat is the most likely diagnosis of this patient?","explanation":null,"reference":"First Aid for the USMLE, Step 1, 2022, page 440","responses":[{"text":"Chronic lymphocytic leukemia (CLL)","correct":true,"visible":false},{"text":"Burkitt's lymphoma","correct":false,"visible":false},{"text":"Acute lymphoblastic leukemia (ALL)","correct":false,"visible":false},{"text":"Diffuse large B cell lymphoma","correct":false,"visible":false},{"text":"Hairy cell lymphoma","correct":false,"visible":false}]},{"id":14392,"text":"A 29 year-old-patient, who is 15 days post-op after delivering a baby via c-section, presents to the clinic with complaints of localized swelling in her right lower limb. The swelling has increased in size over 2 days and is associated with pain and erythema. On examination, the swelling is warm to the touch and tender, and the circumference of the affected leg is 5 cm larger than the unaffected leg. \r\nWhich of the following is the preferred initial test in this patient for establishing diagnosis?","explanation":"According to the Wells criteria, this patient has a high pretest probability (PTP) for DVT (Wells score = 3 in this case), therefore, a Doppler US is the best initial test. \r\n(Doppler Ultrasounds are indicated when Well score ≥ 1)\r\n\r\nD-dimer levels are indicated when the PTP for DVT is low (i.e well score = 0)","reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 188, 189","responses":[{"text":"CT angiography of lower limb","correct":false,"visible":false},{"text":"CT venography of lower limb","correct":false,"visible":false},{"text":"Serum D-dimer levels","correct":false,"visible":false},{"text":"CT angiography of chest","correct":false,"visible":false},{"text":"Doppler ultrasound scan of lower limb","correct":true,"visible":false}]},{"id":14402,"text":"A patient presents to the clinic with complaints of fatigue and exertional dyspnea. On examination, she has yellow discoloration of skin and sclera, subconjunctival pallor, and her spleen can be palpated 2cm below the costal margin. \r\nThe physician suspects intravascular hemolytic anemia and prescribes the relevant laboratory workup. \r\nWhich of the following findings does the physician not expect to see on laboratory reports?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 946.","responses":[{"text":"Elevated serum haptoglobin","correct":true,"visible":false},{"text":"Elevated corrected reticulocyte count","correct":false,"visible":false},{"text":"Increased urinary urobilinogen","correct":false,"visible":false},{"text":"Elevated serum indirect (unconjugated) bilirubin","correct":false,"visible":false},{"text":"Elevated serum lactate dehydrogenase (LDH)","correct":false,"visible":false}]},{"id":14424,"text":"A young female presents to the clinic with complaints of exertional dyspnea, fatigue, and diarrhea. Stool examination shows the presence of proglottids. CBC shows Hb = 8 g/dL, MCV = 110, presence of hyper-segmented neutrophils and eosinophilia. The physician is suspecting a worm infection. \r\nWhich of the following species is this patient most likely infected by?","explanation":null,"reference":"Harrison's Principles of Internal Medicine, 20th edition, pages 705, 1552, 1646. \r\nFirst Aid for the USMLE Step 1, 2022, pages  67, 157, 428.","responses":[{"text":"Diphyllobothrium latum","correct":true,"visible":false},{"text":"Ancylostoma duodenale","correct":false,"visible":false},{"text":"Strongyloides stercoralis","correct":false,"visible":false},{"text":"Taenia saginata","correct":false,"visible":false},{"text":"Toxocara canis","correct":false,"visible":false}]},{"id":14426,"text":"A 40-year-old male presents with presents to the clinic with complaints of fever, vomiting, and fatigue for 5 days. On examination, there are petechiae and pallor. Laboratory reports show Hb = 9 g/dL, Platelets = 19,000/mm3, Cr = 6 mg/dL. \r\n\r\nWhat is the most likely cause of this patient's anemia?","explanation":null,"reference":"(1) First Aid for the USMLE Step 1, 2023, page 432.\r\n\r\n(2) Davidson's Principles and Practice of Medicine, 24th edition, page 988.","responses":[{"text":"Immune thrombocytopenic purpura","correct":false,"visible":false},{"text":"Hemolytic uremic syndrome","correct":false,"visible":false},{"text":"Thrombotic thrombocytopenic purpura","correct":true,"visible":false},{"text":"Macroangiopathic hemolytic anemia","correct":false,"visible":false},{"text":"Glanzmann thrombasthenia","correct":false,"visible":false}]},{"id":14794,"text":"Which of the following is the most correct statement regarding an allograft?","explanation":"An **allograft** refers to the transplantation of an organ or tissue from **one individual to another**, typically from a donor to a recipient. When organs or tissues are transplanted between different individuals of the same species, it is referred to as an allograft.\r\n\r\n***\r\n\r\nThe successful positioning of a graft does not address the nature of the graft itself.\r\n\r\nA xenograft involves grafting between different species.\r\n\r\nAllografts can also be placed in their normal anatomical positions.\r\n\r\nAn autograft involves taking a graft from the same individual and transplanting it elsewhere in their body.","reference":"O’Connell, P. Ronan, et al., editors. Bailey \u0026 Love’s Short Practice of Surgery. 28th ed., CRC Press, Taylor \u0026 Francis Group, 2023: 1620.","responses":[{"text":"An organ or tissue transplanted from one individual to another","correct":true,"visible":false},{"text":"A graft placed in a site different from that where the organ is normally located","correct":false,"visible":false},{"text":"A graft placed in its normal position","correct":false,"visible":false},{"text":"A graft performed between different species","correct":false,"visible":false},{"text":"A graft taken from the same individual","correct":false,"visible":false}]},{"id":17838,"text":"Which of the following is the mechanism of action of alteplase?","explanation":"Plasmin is a natural enzyme in the body that plays a vital role in breaking down fibrin, a major component of blood clots. When administered, **alteplase specifically targets and activates plasminogen, converting it into plasmin.** Plasmin then acts as a proteolytic enzyme, breaking down the fibrin mesh within blood clots, effectively dissolving them. This process is known as thrombolysis, and it helps restore blood flow in situations where there is a clot blocking an artery or vein.\r\n\r\nUnlike other medications that inhibit clot formation, alteplase works to actively dissolve existing clots. This makes it a valuable treatment option in conditions such as acute myocardial infarction (heart attack), ischemic stroke, and pulmonary embolism, where rapid clot dissolution can be life-saving. It should be administered under careful medical supervision due to its potent thrombolytic effects.","reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 306.","responses":[{"text":"Inhibits coagulation factor VIII","correct":false,"visible":false},{"text":"Causes vasodilation","correct":false,"visible":false},{"text":"Inhibition of glycoprotein IIb/IIIa","correct":false,"visible":false},{"text":"Activates tissue plasminogen to plasmin","correct":true,"visible":false},{"text":"Decreases cAMP","correct":false,"visible":false}]},{"id":20078,"text":"A 45-year-old patient presents with a history of recurrent infections, easy bruising, and persistent fatigue. Further evaluation reveals anemia. What is the most likely cause of these symptoms in this patient?","explanation":null,"reference":"Davidson’s Principles and Practice of Medicine, 24th edition, pages 968.","responses":[{"text":"Iron-deficiency anemia","correct":false,"visible":false},{"text":"Leukemia","correct":false,"visible":false},{"text":"Hemophilia","correct":false,"visible":false},{"text":"Sickle cell anemia","correct":false,"visible":false},{"text":"Aplastic anemia","correct":true,"visible":false}]},{"id":20079,"text":"A 12-year-old patient presents with a history of fatigue and yellowish discoloration of the sclera. On abdominal examination, splenomegaly is appreciated. An electrophoresis test is performed to evaluate the hemoglobin levels. What is the expected electrophoresis finding in a patient with beta-thalassemia major?","explanation":null,"reference":"Davidson’s Principles and Practice of Medicine, 24th edition, page 954.","responses":[{"text":"Elevated hemoglobin C (HbC) levels","correct":false,"visible":false},{"text":"Decreased hemoglobin S (HbS) levels","correct":false,"visible":false},{"text":"Elevated hemoglobin A (HbA) levels","correct":false,"visible":false},{"text":"Elevated hemoglobin A2 (HbA2) levels","correct":false,"visible":false},{"text":"Elevated hemoglobin F (HbF) levels","correct":true,"visible":false}]}
]

export default a